const CUISINE_PRESETS = ["Pakistani", "Turkish", "Lebanese", "Malaysian", "Indian", "Moroccan", "Egyptian", "Somali", "Afghan", "Mediterranean"];
const LOCATION_PRESETS = ["Near Me", "Top Rated", "New Openings", "Recently Added"];
