function norm(s) { return (s || "").toLowerCase().replace(/[^a-z0-9]/g, ""); }
function normPhone(p) { return (p || "").replace(/[^0-9]/g, ""); }
function normUrl(u) { return (u || "").toLowerCase().replace(/^https?:\/\//, "").replace(/^www\./, "").replace(/\/+$/, "").trim(); }
function fuzzyName(s) { return norm((s || "").replace(/^the\s+/i, "").replace(/\s+(restaurant|halal|llc|inc|corp|grill|kitchen|house|cafe|diner|eatery|bistro|lounge)$/i, "")); }
function extractStreet(addr) {
  const clean = (addr || "").trim().toLowerCase();
  const street = clean.split(",")[0].trim();
  return street.replace(/\b(suite|ste|unit|apt|#)\s*\w*/gi, "").replace(/\s+/g, " ").trim();
}
function autoGmaps(name, addr) {
  if (!addr) return "";
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(name + " " + addr)}`;
}
// Non-restaurant keywords to filter
const NON_RESTAURANT = /\b(grocery|supermarket|market|mart|butcher|slaughter|wholesale|distributor|supplier|catering only|mosque|masjid|islamic center|school|academy)\b/i;
function isNonRestaurant(r) {
  return NON_RESTAURANT.test(r.name || "") || NON_RESTAURANT.test(r.cuisine || "") || NON_RESTAURANT.test(r.notes || "");
}
// Auto-detect halal level from source/notes
function detectHalalLevel(r) {
  const src = ((r.source || "") + " " + (r.notes || "")).toLowerCase();
  if (/zabiha\.com|zabihamap|hand.slaughter|zabiha certified/i.test(src)) return "Zabiha Only";
  if (/halal.certified|halalfoundation|hmsusa|ifanca|isna certified|hmc certified/i.test(src)) return "Fully Halal";
  if (/halal options|some halal|partial/i.test(src)) return "Halal Options";
  if (/fully halal|all halal|100%.halal|all meat halal/i.test(src)) return "Fully Halal";
  return "Unverified";
}
function isKnown(name, addr, phone, website, db) {
  const n = norm(name), fn = fuzzyName(name), a = norm(addr), p = normPhone(phone);
  const street = extractStreet(addr);
  const streetNorm = norm(street);
  const w = normUrl(website);
  return db.some(r => {
    // Exact name match
    if (n && norm(r.name) === n) return true;
    // Fuzzy name match
    if (fn && fn.length > 3 && fuzzyName(r.name) === fn) return true;
    // Phone match
    if (p && p.length >= 7 && normPhone(r.phone) === p) return true;
    // Website match
    if (w && w.length > 3 && normUrl(r.website) === w) return true;
    // Full address match
    if (a && a.length > 5 && norm(r.address) === a) return true;
    // Street-level address match
    if (streetNorm && streetNorm.length > 5) {
      const dbStreet = norm(extractStreet(r.address));
      if (dbStreet && dbStreet.length > 5 && dbStreet === streetNorm) return true;
      if (dbStreet.length > 10 && streetNorm.length > 10) {
        if (dbStreet.includes(streetNorm) || streetNorm.includes(dbStreet)) return true;
      }
    }
    return false;
  });
}
// Partial/maybe match for "maybe duplicate" detection
function isMaybeDuplicate(name, addr, phone, website, db) {
  const fn = fuzzyName(name);
  const w = normUrl(website);
  return db.some(r => {
    const rFn = fuzzyName(r.name);
    // Fuzzy name contains
    if (fn.length > 5 && rFn.length > 5 && (fn.includes(rFn) || rFn.includes(fn))) return true;
    // Website partial match
    if (w && w.length > 5 && normUrl(r.website) && (w.includes(normUrl(r.website)) || normUrl(r.website).includes(w))) return true;
    return false;
  });
}

function useTheme(pref) {
  const [dark, setDark] = useState(false);
  useEffect(() => {
    if (pref === "light") { setDark(false); return; }
    if (pref === "dark") { setDark(true); return; }
    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    setDark(mq.matches);
    const h = e => setDark(e.matches);
    mq.addEventListener("change", h);
    return () => mq.removeEventListener("change", h);
  }, [pref]);
  return dark;
}

