// ─── STORAGE ────────────────────────────────────────────────────────
async function load(key, fallback = []) {
  try { const r = localStorage.getItem(key); return r ? JSON.parse(r) : fallback; } catch(e) { return fallback; }
}
async function save(key, val) {
  try { localStorage.setItem(key, JSON.stringify(val)); } catch (e) { console.error("save fail", e); }
}

// ─── CALIFORNIA SEED (compact: name\tstreet\tcity\tphone\tcuisine) ───
const CA_SEED = "";
async function decompressSeed() {
  try {
    const bin = Uint8Array.from(atob(CA_SEED), c => c.charCodeAt(0));
    const ds = new DecompressionStream("gzip");
    const w = ds.writable.getWriter(); w.write(bin); w.close();
    const rd = ds.readable.getReader();
    const ch = []; let done = false;
    while (!done) { const r = await rd.read(); if (r.done) break; ch.push(r.value); }
    const total = ch.reduce((a,c) => a + c.length, 0);
    const all = new Uint8Array(total); let off = 0;
    for (const c of ch) { all.set(c, off); off += c.length; }
    const text = new TextDecoder().decode(all);
    return text.split("\n").filter(Boolean).map(line => {
      const [name,street,city,phone,cuisine] = line.split("\t");
      return { name, address: [street,city,"California"].filter(Boolean).join(", "), phone: phone || "", cuisine: cuisine || "", halalLevel: "Unverified", source: "CA Database", addedAt: "2026-04-04T00:00:00.000Z", notes: "", website: "", gmaps: name && (street||city) ? "https://www.google.com/maps/search/?api=1&query="+encodeURIComponent(name+" "+(street||"")+" "+(city||"")) : "", instagram: "" };
    });
  } catch(e) { console.error("Seed failed:", e); return []; }
}


// ─── EXPORT HELPERS ─────────────────────────────────────────────────
// Robust JSON array extraction — handles truncated/malformed responses
function safeParseJsonArray(text) {
  if (!text) return [];
  const m = text.match(/\[[\s\S]*\]/);
  if (!m) return [];
  let raw = m[0];
  try { return JSON.parse(raw).filter(r => r && typeof r === "object"); } catch(e) {}
  try {
    raw = raw.replace(/,\s*\{[^}]*$/, "");
    if (!raw.trim().endsWith("]")) raw = raw.trim() + "]";
    raw = raw.replace(/,\s*\]/g, "]");
    return JSON.parse(raw).filter(r => r && typeof r === "object");
  } catch(e) {}
  try {
    const objs = [];
    const objMatches = raw.matchAll(/\{[^{}]*\}/g);
    for (const om of objMatches) {
      try { const o = JSON.parse(om[0]); if (o && o.name) objs.push(o); } catch(e) {}
    }
    return objs;
  } catch(e) { return []; }
}

function genCSV(db) {
  const headers = "Name,Address,Phone,Cuisine,Halal Level,Notes,Website,Google Maps,Instagram,Source\n";
  const rows = db.map(r => [r.name,r.address,r.phone,r.cuisine,r.halalLevel,r.notes,r.website,r.gmaps,r.instagram,r.source].map(v => `"${(v||"").replace(/"/g,'""')}"`).join(",")).join("\n");
  return headers + rows;
}
function genJSON(db) { return JSON.stringify(db, null, 2); }
async function copyToClipboard(text) {
  try { await navigator.clipboard.writeText(text); return true; } catch(e) { return false; }
}

