// ─── SETTINGS MODAL ─────────────────────────────────────────────────
function SettingsModal({ settings, onSave, onClose, db, onImport, t }) {
  const [s, setS] = useState(settings);
  const [exportView, setExportView] = useState(null); // null | "csv" | "json"
  const [exportText, setExportText] = useState("");
  const [importText, setImportText] = useState("");
  const [importMsg, setImportMsg] = useState(null);
  const [copyMsg, setCopyMsg] = useState(null);
  const set = (k,v) => setS(p=>({...p,[k]:v}));

  const handleExport = (fmt) => {
    const text = fmt === "csv" ? genCSV(db) : genJSON(db);
    setExportText(text);
    setExportView(fmt);
  };
  const handleCopy = async () => {
    const ok = await copyToClipboard(exportText);
    setCopyMsg(ok ? "✅ Copied to clipboard!" : "❌ Copy failed — select all and copy manually");
    setTimeout(() => setCopyMsg(null), 3000);
  };
  const handleImport = () => {
    if (!importText.trim()) { setImportMsg("❌ Paste your data first"); return; }
    try {
      let imported;
      const trimmed = importText.trim();
      if (trimmed.startsWith("[")) {
        imported = JSON.parse(trimmed);
      } else {
        // CSV parsing
        const lines = trimmed.split("\n").slice(1);
        imported = lines.filter(l=>l.trim()).map(l=>{
          const cols = l.match(/(".*?"|[^,]+)/g)?.map(c=>c.replace(/^"|"$/g,"").replace(/""/g,'"')) || [];
          return { name:cols[0]||"", address:cols[1]||"", phone:cols[2]||"", cuisine:cols[3]||"", halalLevel:cols[4]||"", notes:cols[5]||"", website:cols[6]||"", gmaps:cols[7]||"", instagram:cols[8]||"", source:cols[9]||"" };
        });
      }
      if (!Array.isArray(imported) || !imported.length) { setImportMsg("❌ No valid data found"); return; }
      onImport(imported);
      setImportText("");
      setImportMsg(`✅ Import successful!`);
      setTimeout(() => setImportMsg(null), 3000);
    } catch(e) { setImportMsg("❌ Invalid format — use JSON array or CSV"); }
  };

  return (
    <div style={{ position:"fixed", inset:0, zIndex:9999, background:t.overlay, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onClose}>
      <div style={{ background:t.card, borderRadius:14, padding:20, width:"100%", maxWidth:420, maxHeight:"85vh", overflowY:"auto" }} onClick={e=>e.stopPropagation()}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <div style={{ fontWeight:700, fontSize:17, color:t.text }}>{exportView ? `Export ${exportView.toUpperCase()}` : "Settings"}</div>
          <button onClick={exportView ? ()=>setExportView(null) : onClose} style={{ background:"none", border:"none", cursor:"pointer", color:t.sub }}>{exportView ? <span style={{fontSize:13,fontWeight:600}}>← Back</span> : <X size={20}/>}</button>
        </div>

        {exportView ? (
          <>
            <textarea value={exportText} readOnly style={{ width:"100%", height:200, padding:10, borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:11, fontFamily:"'JetBrains Mono',monospace", resize:"vertical", boxSizing:"border-box", lineHeight:1.5 }} onFocus={e=>e.target.select()} />
            <button onClick={handleCopy} style={{ width:"100%", padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg, #1e3a5f, #2563eb)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", marginTop:8 }}>📋 Copy to Clipboard</button>
            {copyMsg && <div style={{ textAlign:"center", fontSize:12, fontWeight:600, color: copyMsg.startsWith("✅") ? "#22c55e" : "#dc2626", marginTop:8 }}>{copyMsg}</div>}
            <p style={{ fontSize:11, color:t.muted, textAlign:"center", marginTop:8 }}>Or tap the text box, select all, and copy manually</p>
          </>
        ) : (
          <>
            <label style={{ fontSize:11, fontWeight:700, color:t.sub, textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", display:"block", marginBottom:6 }}>Theme</label>
            <div style={{ display:"flex", gap:6, marginBottom:14 }}>
              {["auto","light","dark"].map(v=>(
                <button key={v} onClick={()=>set("theme",v)} style={{ flex:1, padding:"8px", borderRadius:8, border: s.theme===v ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: s.theme===v ? "#2563eb18" : t.input, color: s.theme===v ? "#2563eb" : t.sub, fontSize:12, fontWeight:600, cursor:"pointer", textTransform:"capitalize" }}>{v}</button>
              ))}
            </div>
            <label style={{ fontSize:11, fontWeight:700, color:t.sub, textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", display:"block", marginBottom:6 }}>Default Search Location</label>
            <input value={s.defaultLocation||""} onChange={e=>set("defaultLocation",e.target.value)} placeholder="e.g. Chicago, IL" style={{ width:"100%", padding:"9px 12px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:13, fontFamily:"inherit", boxSizing:"border-box", marginBottom:14 }} />

            <label style={{ fontSize:11, fontWeight:700, color:t.sub, textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", display:"block", marginBottom:6 }}>Export Database ({db.length} restaurants)</label>
            <div style={{ display:"flex", gap:8, marginBottom:14 }}>
              <button onClick={()=>handleExport("csv")} style={{ flex:1, padding:"10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:12, fontWeight:600, cursor:"pointer" }}>📤 Export CSV</button>
              <button onClick={()=>handleExport("json")} style={{ flex:1, padding:"10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:12, fontWeight:600, cursor:"pointer" }}>📤 Export JSON</button>
            </div>

            <label style={{ fontSize:11, fontWeight:700, color:t.sub, textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", display:"block", marginBottom:6 }}>Import (Paste CSV or JSON)</label>
            <textarea value={importText} onChange={e=>setImportText(e.target.value)} placeholder='Paste JSON array or CSV data here…' style={{ width:"100%", height:80, padding:10, borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:11, fontFamily:"'JetBrains Mono',monospace", resize:"vertical", boxSizing:"border-box", marginBottom:6 }} />
            <button onClick={handleImport} disabled={!importText.trim()} style={{ width:"100%", padding:"10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background: importText.trim() ? t.input : t.bg, color: importText.trim() ? t.text : t.muted, fontSize:12, fontWeight:600, cursor: importText.trim() ? "pointer" : "default", marginBottom:6 }}>📥 Import Data</button>
            {importMsg && <div style={{ fontSize:12, fontWeight:600, color: importMsg.startsWith("✅") ? "#22c55e" : "#dc2626", marginBottom:10, textAlign:"center" }}>{importMsg}</div>}

            <button onClick={()=>{onSave(s);onClose();}} style={{ width:"100%", padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg, #1e3a5f, #2563eb)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", marginTop:6 }}>Save Settings</button>
          </>
        )}
      </div>
    </div>
  );
}

// ─── AI VERIFY CALL MODAL ────────────────────────────────────────
function VerifyModal({ restaurant, onSave, onClose, t }) {
  const [step, setStep] = useState("ready"); // ready | calling | transcript | log
  const [transcript, setTranscript] = useState([]);
  const [callStatus, setCallStatus] = useState("");
  const [callTime, setCallTime] = useState(0);
  const [isHalal, setIsHalal] = useState("");
  const [meats, setMeats] = useState({ chicken: "", beef: "", lamb: "", goat: "", other: "" });
  const [halalLevel, setHalalLevel] = useState("");
  const [notes, setNotes] = useState("");
  const [aiResult, setAiResult] = useState(null);
  const timerRef = useRef(null);

  const meatLabels = { chicken: "Chicken", beef: "Beef", lamb: "Lamb", goat: "Goat", other: "Other" };

  const startAiCall = async () => {
    setStep("calling");
    setCallStatus("Dialing...");
    setTranscript([]);
    setCallTime(0);
    const start = Date.now();
    timerRef.current = setInterval(() => setCallTime(Math.floor((Date.now() - start) / 1000)), 1000);

    await new Promise(r => setTimeout(r, 500));
    setCallStatus("Ringing...");
    await new Promise(r => setTimeout(r, 500));
    setCallStatus("Connected");
    setTranscript([{ role: "system", text: "Call connected" }]);
    await new Promise(r => setTimeout(r, 200));

    try {
      const resp = await fetch("/api/search", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514", max_tokens: 1500,
          messages: [{ role: "user", content: `Simulate a realistic phone call between a polite AI assistant and "${restaurant.name}" (${restaurant.cuisine || "restaurant"} in ${restaurant.address || "unknown"}).

The AI is warm, courteous, and friendly:
1. Greets with "Hi, how are you doing today?"
2. Says "I was just calling to ask, is your food halal?"
3. If yes, asks "That's great, thank you! Which meats do you serve halal?"
4. Thanks them warmly: "Thank you so much, I really appreciate your time!"

Simulate what the restaurant staff would realistically say based on this type of restaurant.

Return ONLY a JSON object (no markdown):
{"lines":[{"speaker":"ai","text":"..."},{"speaker":"restaurant","text":"..."}],"result":{"isHalal":"yes/some/no","level":"Fully Halal/Zabiha Only/Halal Options/Not Halal","chicken":"halal/not/na","beef":"halal/not/na","lamb":"halal/not/na","goat":"halal/not/na","summary":"one sentence"}}` }],
        }),
      });
      const data = await resp.json();
      const text = (data.content || []).map(b => b.text || "").join("");
      const m = text.match(/\{[\s\S]*\}/);
      if (m) {
        const parsed = JSON.parse(m[0]);
        const convLines = parsed.lines || [];
        for (let i = 0; i < convLines.length; i++) {
          await new Promise(r => setTimeout(r, 300 + Math.random() * 300));
          setTranscript(prev => [...prev, convLines[i]]);
        }
        if (parsed.result) {
          setAiResult(parsed.result);
          setIsHalal(parsed.result.isHalal || "");
          setHalalLevel(parsed.result.level || "");
          setNotes(parsed.result.summary || "");
          setMeats({ chicken: parsed.result.chicken || "", beef: parsed.result.beef || "", lamb: parsed.result.lamb || "", goat: parsed.result.goat || "", other: "" });
        }
      }
    } catch(e) {
      setTranscript(prev => [...prev, { role: "system", text: "Call failed" }]);
    }
    clearInterval(timerRef.current);
    setCallStatus("Call ended");
    await new Promise(r => setTimeout(r, 200));
    setStep("transcript");
  };

  useEffect(() => { return () => clearInterval(timerRef.current); }, []);

  const handleSave = () => {
    const meatSummary = Object.entries(meats).filter(([,v]) => v && v !== "na").map(([k,v]) => `${k}: ${v}`).join(", ");
    const verification = {
      halalLevel: halalLevel || (isHalal === "yes" ? "Fully Halal" : isHalal === "some" ? "Halal Options" : isHalal === "no" ? "Not Halal" : "Unverified"),
      notes: [restaurant.notes, `AI CALLED ${new Date().toLocaleDateString()}: ${isHalal === "yes" ? "Confirmed halal" : isHalal === "some" ? "Some halal" : isHalal === "no" ? "Not halal" : "Unknown"}${meatSummary ? ". Meats: " + meatSummary : ""}${notes ? ". " + notes : ""}`].filter(Boolean).join(" | "),
      verifiedAt: new Date().toISOString(),
    };
    onSave({ ...restaurant, ...verification });
    onClose();
  };

  const fmtTime = (s) => `${Math.floor(s/60)}:${String(s%60).padStart(2,"0")}`;

  return (
    <div style={{ position:"fixed", inset:0, zIndex:9999, background:t.overlay, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onClose}>
      <div style={{ background:t.card, borderRadius:14, padding:20, width:"100%", maxWidth:420, maxHeight:"85vh", overflowY:"auto" }} onClick={e=>e.stopPropagation()}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
          <div style={{ fontWeight:700, fontSize:16, color:t.text }}>AI Halal Verification</div>
          <button onClick={onClose} style={{ background:"none", border:"none", cursor:"pointer", color:t.sub }}><X size={20}/></button>
        </div>

        <div style={{ background:t.bg, borderRadius:10, padding:12, marginBottom:14 }}>
          <div style={{ fontWeight:700, fontSize:14, color:t.text }}>{restaurant.name}</div>
          {restaurant.cuisine && <div style={{ fontSize:11, color:t.sub, fontStyle:"italic" }}>{restaurant.cuisine}</div>}
          {restaurant.address && <div style={{ fontSize:11, color:t.sub, marginTop:2 }}>📍 {restaurant.address}</div>}
          {restaurant.phone && <div style={{ fontSize:11, color:t.sub, marginTop:2 }}>📞 {restaurant.phone}</div>}
        </div>

        {step === "ready" && (
          <>
            <div style={{ background:t.bg, borderRadius:10, padding:14, marginBottom:14, lineHeight:1.6 }}>
              <div style={{ fontSize:12, fontWeight:700, color:t.text, marginBottom:8 }}>AI will politely ask:</div>
              <div style={{ fontSize:12, color:t.sub }}>1. "Hi there, how are you doing today?"<br/>2. "Is your food halal?"<br/>3. "Which meats are halal?"<br/>4. "Thank you so much, have a great day!"</div>
            </div>
            {restaurant.phone ? (
              <button onClick={startAiCall} style={{ width:"100%", padding:"14px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#059669,#10b981)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}><Phone size={16}/> Start AI Call</button>
            ) : (
              <div style={{ textAlign:"center", padding:14, color:"#dc2626", fontSize:12, fontWeight:600 }}>No phone number available</div>
            )}
            <button onClick={()=>setStep("log")} style={{ width:"100%", padding:"10px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.sub, fontSize:12, fontWeight:600, cursor:"pointer", marginTop:10 }}>Or log a manual call</button>
          </>
        )}

        {step === "calling" && (
          <div style={{ textAlign:"center" }}>
            <div style={{ width:80, height:80, borderRadius:"50%", background: callStatus === "Connected" ? "linear-gradient(135deg,#059669,#10b981)" : "linear-gradient(135deg,#1e3a5f,#2563eb)", margin:"0 auto 12px", display:"flex", alignItems:"center", justifyContent:"center", animation: callStatus === "Ringing..." ? "pulse 1s ease infinite" : "none" }}><Phone size={32} color="#fff" /></div>
            <div style={{ fontWeight:700, fontSize:14, color:t.text }}>{callStatus}</div>
            <div style={{ fontSize:24, fontWeight:800, color:"#2563eb", fontFamily:"'JetBrains Mono',monospace", marginTop:4 }}>{fmtTime(callTime)}</div>
            <div style={{ fontSize:11, color:t.muted, marginTop:4, marginBottom:14 }}>{restaurant.name}</div>
            {transcript.length > 0 && (
              <div style={{ textAlign:"left", maxHeight:200, overflowY:"auto", marginBottom:14 }}>
                {transcript.map((line, i) => (
                  <div key={i} style={{ marginBottom:8, animation:"fadeUp .3s ease" }}>
                    {line.role === "system" ? (
                      <div style={{ fontSize:10, color:t.muted, textAlign:"center", fontFamily:"'JetBrains Mono',monospace" }}>— {line.text} —</div>
                    ) : (
                      <div style={{ display:"flex", gap:8 }}>
                        <div style={{ width:26, height:26, borderRadius:"50%", background: line.speaker === "ai" ? "#2563eb" : "#059669", display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, flexShrink:0, color:"#fff" }}>{line.speaker === "ai" ? "AI" : "R"}</div>
                        <div style={{ flex:1, background:t.bg, borderRadius:10, padding:"8px 12px", fontSize:12, color:t.text, lineHeight:1.4 }}>{line.text}</div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
            <div style={{ fontSize:10, color:t.muted, animation:"pulse 1.4s ease infinite" }}>Listening...</div>
          </div>
        )}

        {step === "transcript" && (
          <>
            <div style={{ fontSize:12, fontWeight:700, color:t.text, marginBottom:8 }}>Call Transcript</div>
            <div style={{ maxHeight:180, overflowY:"auto", marginBottom:14 }}>
              {transcript.filter(l => l.role !== "system").map((line, i) => (
                <div key={i} style={{ display:"flex", gap:8, marginBottom:8 }}>
                  <div style={{ width:22, height:22, borderRadius:"50%", background: line.speaker === "ai" ? "#2563eb" : "#059669", display:"flex", alignItems:"center", justifyContent:"center", fontSize:9, flexShrink:0, color:"#fff", fontWeight:700 }}>{line.speaker === "ai" ? "AI" : "R"}</div>
                  <div style={{ flex:1, fontSize:12, color:t.sub, lineHeight:1.4 }}>{line.text}</div>
                </div>
              ))}
            </div>
            {aiResult && (
              <div style={{ textAlign:"center", background:t.bg, borderRadius:10, padding:14, marginBottom:14 }}>
                <div style={{ fontSize:32, marginBottom:4 }}>{isHalal === "yes" ? "✅" : isHalal === "some" ? "🔶" : isHalal === "no" ? "❌" : "❓"}</div>
                <div style={{ fontWeight:800, fontSize:18, color:t.text }}>{halalLevel || "Unverified"}</div>
                {notes && <div style={{ fontSize:11, color:t.sub, marginTop:4 }}>{notes}</div>}
              </div>
            )}
            {(isHalal === "yes" || isHalal === "some") && (
              <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:14 }}>
                {Object.entries(meatLabels).map(([k,label]) => meats[k] && meats[k] !== "na" ? (
                  <span key={k} style={{ fontSize:11, padding:"3px 10px", borderRadius:6, background: meats[k]==="halal" ? "#05966918" : "#dc262618", color: meats[k]==="halal" ? "#059669" : "#dc2626", fontWeight:600 }}>{label} {meats[k]==="halal" ? "✅" : "❌"}</span>
                ) : null)}
              </div>
            )}
            <div style={{ fontSize:11, fontWeight:700, color:t.sub, marginBottom:6 }}>Adjust if needed:</div>
            <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginBottom:14 }}>
              {["Fully Halal","Zabiha Only","Halal Options","Not Halal","Unverified"].map(lvl => (
                <button key={lvl} onClick={()=>setHalalLevel(lvl)} style={{ padding:"5px 10px", borderRadius:6, border: halalLevel === lvl ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: halalLevel === lvl ? "#2563eb18" : t.input, color: halalLevel === lvl ? "#2563eb" : t.sub, fontSize:10, fontWeight:600, cursor:"pointer" }}>{lvl}</button>
              ))}
            </div>
            <button onClick={handleSave} style={{ width:"100%", padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>Save Verification</button>
          </>
        )}

        {step === "log" && (
          <>
            {restaurant.phone && <a href={`tel:${restaurant.phone}`} style={{ display:"inline-flex", alignItems:"center", gap:6, marginBottom:12, padding:"8px 16px", borderRadius:8, background:"linear-gradient(135deg,#059669,#10b981)", color:"#fff", fontWeight:700, fontSize:13, textDecoration:"none" }}><Phone size={14}/> Call {restaurant.phone}</a>}
            <div style={{ fontSize:12, fontWeight:700, color:t.text, marginBottom:8 }}>Is the food halal?</div>
            <div style={{ display:"flex", gap:6, marginBottom:14 }}>
              {[["yes","Yes ✅"],["some","Some 🔶"],["no","No ❌"],["na","N/A 📵"]].map(([val,label]) => (
                <button key={val} onClick={()=>setIsHalal(val)} style={{ flex:1, padding:"8px 4px", borderRadius:8, border: isHalal === val ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: isHalal === val ? "#2563eb18" : t.input, color: isHalal === val ? "#2563eb" : t.sub, fontSize:10, fontWeight:600, cursor:"pointer" }}>{label}</button>
              ))}
            </div>
            {(isHalal === "yes" || isHalal === "some") && (
              <div style={{ display:"flex", flexDirection:"column", gap:6, marginBottom:14 }}>
                {Object.entries(meatLabels).map(([key, label]) => (
                  <div key={key} style={{ display:"flex", alignItems:"center", gap:6 }}>
                    <span style={{ fontSize:12, width:70, color:t.sub }}>{label}</span>
                    <div style={{ display:"flex", gap:4, flex:1 }}>
                      {[["halal","Halal ✅"],["not","No"],["na","N/A"]].map(([val,lbl]) => (
                        <button key={val} onClick={()=>setMeats(prev=>({...prev,[key]:val}))} style={{ flex:1, padding:"5px 2px", borderRadius:6, border: meats[key] === val ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: meats[key] === val ? "#2563eb18" : t.input, color: meats[key] === val ? "#2563eb" : t.sub, fontSize:9, fontWeight:600, cursor:"pointer" }}>{lbl}</button>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
            <textarea value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Notes..." style={{ width:"100%", height:50, padding:10, borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:12, fontFamily:"inherit", resize:"vertical", boxSizing:"border-box", marginBottom:10 }}/>
            <button onClick={handleSave} disabled={!isHalal} style={{ width:"100%", padding:"12px", border:"none", borderRadius:10, background: isHalal ? "linear-gradient(135deg,#1e3a5f,#2563eb)" : t.inputBorder, color:"#fff", fontWeight:700, fontSize:14, cursor: isHalal ? "pointer" : "default" }}>Save</button>
          </>
        )}
      </div>
    </div>
  );
}

// ─── CONFIRM MODAL ──────────────────────────────────────────────────
function ConfirmModal({ title, message, onConfirm, onCancel, t, danger }) {
  return (
    <div style={{ position:"fixed", inset:0, zIndex:9999, background:t.overlay, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onCancel}>
      <div style={{ background:t.card, borderRadius:14, padding:20, width:"100%", maxWidth:340, textAlign:"center" }} onClick={e=>e.stopPropagation()}>
        <div style={{ fontSize:32, marginBottom:8 }}>{danger ? "⚠️" : "🗑️"}</div>
        <div style={{ fontWeight:700, fontSize:16, color:t.text, marginBottom:6 }}>{title}</div>
        <div style={{ fontSize:13, color:t.sub, marginBottom:16, lineHeight:1.5 }}>{message}</div>
        <div style={{ display:"flex", gap:8 }}>
          <button onClick={onCancel} style={{ flex:1, padding:"10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontWeight:600, fontSize:13, cursor:"pointer" }}>Cancel</button>
          <button onClick={onConfirm} style={{ flex:1, padding:"10px", borderRadius:8, border:"none", background: danger ? "#dc2626" : "#2563eb", color:"#fff", fontWeight:700, fontSize:13, cursor:"pointer" }}>{danger ? "Delete" : "Confirm"}</button>
        </div>
      </div>
    </div>
  );
}

// ─── RESTAURANT CARD ────────────────────────────────────────────────
function Card({ r, isNew, onAdd, onRemove, onRestore, onEdit, onShare, onNav, onFave, onUnfave, onVerify, faved, idx, compact, dimmed, selectable, selected, onSelect, t }) {
  const [expanded, setExpanded] = useState(false);
  const delay = `${idx * 40}ms`;
  return (
    <div
      onClick={() => !selectable && setExpanded(!expanded)}
      style={{
        background: t.card, borderRadius: 12, padding: compact ? "10px 14px" : "14px 16px",
        boxShadow: "0 1px 4px rgba(0,0,0,.06)",
        border: isNew ? "1.5px solid #22c55e" : `1px solid ${t.cardBorder}`,
        display: "flex", flexDirection: "column", gap: compact ? 4 : 8,
        animation: "fadeUp .4s ease both", animationDelay: delay,
        opacity: dimmed ? 0.45 : 1, cursor: selectable ? "pointer" : "default",
        transition: "transform .15s, box-shadow .15s",
        position: "relative",
      }}
      onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,.1)"; }}
      onMouseLeave={e => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = "0 1px 4px rgba(0,0,0,.06)"; }}
    >
      {selectable && (
        <div onClick={e => { e.stopPropagation(); onSelect(r); }} style={{ position:"absolute", top:10, left:10, width:20, height:20, borderRadius:4, border: selected ? "none" : `2px solid ${t.muted}`, background: selected ? "#2563eb" : "transparent", display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer" }}>
          {selected && <Check size={14} color="#fff" />}
        </div>
      )}
      {isNew && <div style={{ position:"absolute", top:0, right:0, background:"#22c55e", color:"#fff", fontSize:9, fontWeight:800, padding:"2px 10px 2px 12px", borderRadius:"0 0 0 8px", letterSpacing:".06em", fontFamily:"'JetBrains Mono',monospace" }}>NEW</div>}

      <div style={{ display:"flex", alignItems:"center", gap:10, marginLeft: selectable ? 28 : 0 }}>
        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ fontFamily:"'Playfair Display',Georgia,serif", fontSize: compact ? 14 : 16, fontWeight:700, color:t.text, lineHeight:1.25 }}>{r.name}</div>
          <div style={{ display:"flex", gap:6, alignItems:"center", marginTop:2, flexWrap:"wrap" }}>
            {r.cuisine && <span style={{ fontSize:11, color:t.sub, fontStyle:"italic" }}>{r.cuisine}</span>}
            {r.halalLevel && <Pill color={HALAL_COLORS[r.halalLevel] || "#6b7280"} small>{r.halalLevel}</Pill>}
            {r.verifiedAt && <span style={{ fontSize:8, color:"#059669", fontWeight:800, fontFamily:"'JetBrains Mono',monospace", background:"#05966915", padding:"1px 5px", borderRadius:4, border:"1px solid #05966930" }}>📞 VERIFIED</span>}
            {r._verified && !r.verifiedAt && <span style={{ fontSize:8, color:"#059669", fontWeight:800, fontFamily:"'JetBrains Mono',monospace", background:"#05966915", padding:"1px 5px", borderRadius:4, border:"1px solid #05966930" }}>✅ AI VERIFIED</span>}
            {r._verifyNote && <span style={{ fontSize:8, color:"#f59e0b", fontWeight:600, fontFamily:"'JetBrains Mono',monospace", background:"#f59e0b12", padding:"1px 5px", borderRadius:4, border:"1px solid #f59e0b30" }}>{r._verifyNote}</span>}
            {r.source && <span style={{ fontSize:9, color:t.muted, fontFamily:"'JetBrains Mono',monospace", background: t.bg, padding:"1px 6px", borderRadius:4 }}>via {r.source}</span>}
          </div>
        </div>
        {!compact && <ChevronDown size={16} color={t.muted} style={{ transform: expanded ? "rotate(180deg)" : "", transition:".2s" }} />}
      </div>

      {r.address && <div onClick={e => { e.stopPropagation(); onNav?.(r.address); }} style={{ fontSize:12, color:t.sub, lineHeight:1.4, cursor:"pointer" }}>📍 {r.address}</div>}
      {r._noAddr && <div style={{ fontSize:10, color:"#f59e0b", fontWeight:600, fontFamily:"'JetBrains Mono',monospace" }}>⚠️ No address found</div>}
      {r._unverified && <div style={{ display:"inline-block", fontSize:9, color:"#dc2626", fontWeight:700, background:"#dc262618", borderRadius:4, padding:"1px 6px", marginTop:2, fontFamily:"'JetBrains Mono',monospace" }}>UNVERIFIED</div>}

      {r.address && !compact && (
        <a href={`https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(r.name + " " + r.address)}`} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{ display:"inline-flex", alignItems:"center", gap:5, marginTop:4, padding:"5px 12px", borderRadius:8, background:"linear-gradient(135deg,#059669,#10b981)", color:"#fff", fontWeight:700, fontSize:11, textDecoration:"none", cursor:"pointer" }}><Navigation size={12}/> Directions</a>
      )}

      {(expanded || !compact) && r.phone && <a href={`tel:${r.phone}`} onClick={e=>e.stopPropagation()} style={{ fontSize:12, color:"#2563eb", textDecoration:"none" }}>📞 {r.phone}</a>}

      {expanded && (
        <div style={{ animation:"fadeUp .2s ease" }}>
          {r.notes && <div style={{ fontSize:12, color:t.sub, background:t.bg, borderRadius:6, padding:"5px 8px", lineHeight:1.4 }}>{r.notes}</div>}
          <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginTop:4 }}>
            {r.website && <a href={r.website} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{ fontSize:11, color:"#2563eb", display:"flex", alignItems:"center", gap:3 }}><Globe size={12}/>Website</a>}
            {r.gmaps && <a href={r.gmaps} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{ fontSize:11, color:"#2563eb", display:"flex", alignItems:"center", gap:3 }}><MapPin size={12}/>Maps</a>}
            {r.instagram && <a href={r.instagram.startsWith("http") ? r.instagram : `https://instagram.com/${r.instagram.replace("@","")}`} target="_blank" rel="noopener noreferrer" onClick={e=>e.stopPropagation()} style={{ fontSize:11, color:"#e1306c", display:"flex", alignItems:"center", gap:3 }}><Instagram size={12}/>IG</a>}
          </div>
          <div style={{ display:"flex", gap:6, marginTop:6 }}>
            {isNew && onAdd && <button onClick={e=>{e.stopPropagation();onAdd(r);}} style={{ flex:1, padding:"7px 0", border:"none", borderRadius:8, background:"linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:12, cursor:"pointer" }}>+ Add</button>}
            {onEdit && <button onClick={e=>{e.stopPropagation();onEdit(r);}} style={{ padding:"7px 12px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.text, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:4 }}><Edit3 size={12}/>Edit</button>}
            {onShare && <button onClick={e=>{e.stopPropagation();onShare(r);}} style={{ padding:"7px 12px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.text, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:4 }}><Share2 size={12}/>Share</button>}
            {onRemove && <button onClick={e=>{e.stopPropagation();onRemove(r);}} style={{ padding:"7px 12px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:"#dc2626", fontSize:11, cursor:"pointer" }}>Remove</button>}
            {onRestore && <button onClick={e=>{e.stopPropagation();onRestore(r);}} style={{ padding:"7px 12px", border:"none", borderRadius:8, background:"#2563eb", color:"#fff", fontSize:11, fontWeight:600, cursor:"pointer" }}>Restore</button>}
          </div>
        </div>
      )}

      {!expanded && !compact && (
        <div style={{ display:"flex", gap:6, marginTop:2 }}>
          {isNew && onAdd && <button onClick={e=>{e.stopPropagation();onAdd(r);}} style={{ flex:1, padding:"7px 0", border:"none", borderRadius:8, background:"linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:12, cursor:"pointer" }}>+ Add to Database</button>}
          {onVerify && <button onClick={e=>{e.stopPropagation();onVerify(r);}} style={{ padding:"7px 10px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background: r.verifiedAt ? "#05966918" : t.input, color: r.verifiedAt ? "#059669" : t.sub, fontSize:11, cursor:"pointer", display:"flex", alignItems:"center", gap:3 }}><Phone size={12}/>{r.verifiedAt ? "✓" : ""}</button>}
          {onFave && <button onClick={e=>{e.stopPropagation();faved ? onUnfave(r) : onFave(r);}} style={{ padding:"7px 10px", border:`1px solid ${faved ? "#f59e0b" : t.inputBorder}`, borderRadius:8, background: faved ? "#f59e0b18" : t.input, color: faved ? "#f59e0b" : t.sub, fontSize:11, cursor:"pointer" }}><Star size={12} fill={faved ? "#f59e0b" : "none"}/></button>}
          {onShare && <button onClick={e=>{e.stopPropagation();onShare(r);}} style={{ padding:"7px 10px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.sub, fontSize:11, cursor:"pointer" }}><Share2 size={12}/></button>}
          {onRemove && !isNew && <button onClick={e=>{e.stopPropagation();onRemove(r);}} style={{ padding:"7px 10px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:"#dc2626", fontSize:11, cursor:"pointer" }}><Trash2 size={12}/></button>}
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// ─── MAIN APP ─────────────────────────────────────────────────────
// VERSION: 2026-04-05-v3-firecrawl
// ═══════════════════════════════════════════════════════════════════
export default function HalalManiacs() {
  const [db, setDb] = useState([]);
  const [trash, setTrash] = useState([]);
  const [faves, setFaves] = useState([]);
  const [settings, setSettings] = useState({ theme:"auto", exportFormat:"csv", defaultLocation:"" });
  const [tab, setTab] = useState("search");
  const [loaded, setLoaded] = useState(false);

  // Search state
  const [query, setQuery] = useState("");
  const [city, setCity] = useState("");
  const [state, setState] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [advCuisine, setAdvCuisine] = useState("");
  const [advHalal, setAdvHalal] = useState("");
  const [showPresets, setShowPresets] = useState(false);
  const [deepSearch, setDeepSearch] = useState(false);
  const [searchTimeLeft, setSearchTimeLeft] = useState(0);
  const [searchPass, setSearchPass] = useState(0);
  const [nextPassIn, setNextPassIn] = useState(0);
  const [currentBatchLabel, setCurrentBatchLabel] = useState("");
  const [currentBatchTag, setCurrentBatchTag] = useState("");
  const [verifying, setVerifying] = useState(false);
  const [verifyProgress, setVerifyProgress] = useState("");
  const searchAbortRef = useRef(null);
  const searchTimerRef = useRef(null);

  // Crawl state
  const [crawlState, setCrawlState] = useState("idle"); // idle | fetching | crawling | paused | done
  const [crawlStateName, setCrawlStateName] = useState("");
  const [crawlCities, setCrawlCities] = useState([]);
  const [crawlSelectedCities, setCrawlSelectedCities] = useState(new Set());
  const [crawlCityIdx, setCrawlCityIdx] = useState(0);
  const [crawlFound, setCrawlFound] = useState(0);
  const [crawlNewFound, setCrawlNewFound] = useState(0);
  const [crawlLog, setCrawlLog] = useState([]);
  const [crawlElapsed, setCrawlElapsed] = useState(0);
  const [crawlCooldown, setCrawlCooldown] = useState(0);
  const [crawlCityPass, setCrawlCityPass] = useState(0);
  const [crawlStateDb, setCrawlStateDb] = useState([]);
  const crawlAbortRef = useRef(null);
  const crawlTimerRef = useRef(null);
  const crawlStateDbRef = useRef([]);
  const PASSES_PER_CITY = 10;
  const PASS_COOLDOWN = 15; // 15s between passes = ~2.5 min per city

  // DB tab state filter
  const [dbViewState, setDbViewState] = useState("all");
  const [availableStates, setAvailableStates] = useState([]);

  // DB state
  const [dbFilter, setDbFilter] = useState("");
  const [dbSort, setDbSort] = useState("date");
  const [dbHalalFilter, setDbHalalFilter] = useState("");
  const [compactView, setCompactView] = useState(false);
  const [selectMode, setSelectMode] = useState(false);
  const [selected, setSelected] = useState(new Set());

  // Modals
  const [editModal, setEditModal] = useState(null);
  const [editIsNew, setEditIsNew] = useState(false);
  const [shareModal, setShareModal] = useState(null);
  const [navModal, setNavModal] = useState(null);
  const [confirmModal, setConfirmModal] = useState(null);
  const [settingsModal, setSettingsModal] = useState(false);
  const [verifyModal, setVerifyModal] = useState(null);
  const [toast, setToast] = useState(null);
  const [tourBanner, setTourBanner] = useState(false);

  const resultsRef = useRef(null);
  const toastTimer = useRef(null);
  const dbRef = useRef(db);
  useEffect(() => { dbRef.current = db; }, [db]);

  const dark = useTheme(settings.theme);
  const t = T(dark);

  // ── Load ──────────────────────────────────────────────────────
  useEffect(() => {
    (async () => {
      try {
        const [d, tr, s, tour, fv] = await Promise.all([load(DB_KEY), load(TRASH_KEY), load(SETTINGS_KEY, {}), load(TOUR_KEY, false), load(FAVES_KEY)]);
        if (d.length) setDb(d);
        if (tr.length) setTrash(tr);
        if (fv.length) setFaves(fv);
        if (Object.keys(s).length) setSettings(prev => ({ ...prev, ...s }));
        if (!tour) setTourBanner(true);
        setLoaded(true);
        // Scan for state databases
        try {
          const states = [];
          for (let i = 0; i < localStorage.length; i++) {
            const key = localStorage.key(i);
            if (key && key.startsWith("hm-db-")) {
              states.push(key.replace("hm-db-", ""));
            }
          }
          setAvailableStates(states);
        } catch(e) {}
        // Seed California DB in background if empty
        if (!d.length) {
          setTimeout(async () => {
            try {
              const seed = await decompressSeed();
              if (seed.length) { setDb(seed); await save(DB_KEY, seed); }
            } catch(e) { console.error("Seed skipped:", e); }
          }, 500);
        }
      } catch(e) {
        console.error("Load failed:", e);
        setLoaded(true);
      }
    })();
  }, []);

  // ── Auto backup ───────────────────────────────────────────────
  useEffect(() => {
    if (!loaded || !db.length) return;
    const doBackup = async () => { await save(BACKUP_KEY, { date: new Date().toISOString(), data: db }); };
    doBackup();
  }, [db, loaded]);

  // Crawl timer cleanup
  useEffect(() => { return () => { if (crawlTimerRef.current) clearInterval(crawlTimerRef.current); }; }, []);

  const showToast = useCallback((msg, undoFn) => {
    clearTimeout(toastTimer.current);
    setToast({ msg, undoFn });
    toastTimer.current = setTimeout(() => setToast(null), 5000);
  }, []);

  const persistDb = useCallback(async (next) => { setDb(next); await save(DB_KEY, next); }, []);
  const persistTrash = useCallback(async (next) => { setTrash(next); await save(TRASH_KEY, next); }, []);
  const persistFaves = useCallback(async (next) => { setFaves(next); await save(FAVES_KEY, next); }, []);
  const persistSettings = useCallback(async (next) => { setSettings(next); await save(SETTINGS_KEY, next); }, []);

  // ── All platforms searched every pass — deeper halal tags each round ─
  // ── Search batches — simple prompts, deeper halal tags each pass ─
  // ── Search passes — same "halal restaurants" query, deeper each pass ─
  const JSON_FMT = 'Return ONLY a valid JSON array. No markdown, no backticks, no text before or after. Each object: {"name":"exact name from listing","address":"exact address from listing","cuisine":"","phone":"exact phone from listing or empty","notes":"","website":"URL if found or empty","gmaps":"","instagram":"","source":"website where you found this"}';

  const makePass = (n) => {
    const searches = [
      "halal restaurants",
      "halal food places",
      "zabihah halal restaurants",
      "halal certified restaurants",
      "halal meat restaurants",
      "halal chicken restaurants",
      "halal burger",
      "halal shawarma kebab",
      "halal biryani curry",
      "halal Mediterranean food",
    ];
    const search = searches[n % searches.length];
    const passLabel = `Pass ${n+1}`;
    return {
      label: passLabel,
      tag: search,
      prompt: (q, ex) => `Search the web for: ${search} ${q}

CRITICAL RULES:
- ONLY include restaurants that appear in your actual search results with a real URL source
- Copy the exact name and address from the listing. Do NOT paraphrase or guess addresses.
- If you cannot find the phone number, leave it as "" — do NOT make one up
- If you can only find 3 restaurants, return only 3. Do NOT invent extras.
- Include the source website where you found each restaurant
- Every address must include street number, street name, city, and state
${ex ? "Filter: " + ex : ""}

${JSON_FMT}`
    };
  };

  const ALL_SOURCE_BATCHES = Array.from({length: 30}, (_, i) => makePass(i));

  const INITIAL_BATCHES = ALL_SOURCE_BATCHES.slice(0, 5);

  // ── Parse JSON from API response ──────────────────────────
  const parseResults = (data) => {
    if (data.error) return [];
    const allText = (data.content||[]).map(b => {
      if (b.type === "text") return b.text;
      if (b.type === "tool_result" && b.content) return typeof b.content === "string" ? b.content : b.content.map(c=>c.text||"").join("\n");
      return "";
    }).join("\n");
    const m = allText.match(/\[[\s\S]*?\]/);
    if (!m) return [];
    try {
      const parsed = JSON.parse(m[0]);
      return (Array.isArray(parsed) ? parsed.filter(r => r && r.name) : [])
        .filter(r => !isNonRestaurant(r)) // Auto-filter non-restaurants
        .map(r => ({
          ...r,
          halalLevel: r.halalLevel || detectHalalLevel(r), // Auto-detect halal level
          gmaps: r.gmaps || autoGmaps(r.name, r.address), // Auto-generate maps link
          _noAddr: !r.address || r.address.trim().length < 3, // Flag no address
          _unverified: (!r.address || r.address.trim().length < 3) && (!r.phone || r.phone.trim().length < 5), // Mark unverified
        }));
    } catch(e) { return []; }
  };

  // ── Deduplicate by name, address, phone, or website ────────────────
  const dedup = (arr) => {
    const result = [];
    const seenNames = new Map();
    const seenFuzzy = new Map();
    const seenStreets = new Map();
    const seenPhones = new Map();
    const seenWebsites = new Map();
    arr.forEach(r => {
      const nameKey = norm(r.name);
      const fuzzyKey = fuzzyName(r.name);
      const streetKey = norm(extractStreet(r.address));
      const phoneKey = normPhone(r.phone);
      const webKey = normUrl(r.website);
      const existing = seenNames.get(nameKey)
        || (fuzzyKey.length > 3 ? seenFuzzy.get(fuzzyKey) : null)
        || (phoneKey.length >= 7 ? seenPhones.get(phoneKey) : null)
        || (webKey.length > 3 ? seenWebsites.get(webKey) : null)
        || (streetKey.length > 5 ? seenStreets.get(streetKey) : null);
      if (!existing) {
        seenNames.set(nameKey, r);
        if (fuzzyKey.length > 3) seenFuzzy.set(fuzzyKey, r);
        if (streetKey.length > 5) seenStreets.set(streetKey, r);
        if (phoneKey.length >= 7) seenPhones.set(phoneKey, r);
        if (webKey.length > 3) seenWebsites.set(webKey, r);
        result.push(r);
      } else {
        // Merge: fill in missing data
        if (!existing.address && r.address) existing.address = r.address;
        if (!existing.phone && r.phone) existing.phone = r.phone;
        if (!existing.cuisine && r.cuisine) existing.cuisine = r.cuisine;
        if (!existing.website && r.website) existing.website = r.website;
        if (!existing.gmaps && r.gmaps) existing.gmaps = r.gmaps;
        if (!existing.instagram && r.instagram) existing.instagram = r.instagram;
        if (r.source && existing.source && !existing.source.includes(r.source)) existing.source += `, ${r.source}`;
        if (!existing.notes && r.notes) existing.notes = r.notes;
        if (existing.halalLevel === "Unverified" && r.halalLevel && r.halalLevel !== "Unverified") existing.halalLevel = r.halalLevel;
        // Update flags
        existing._noAddr = !existing.address || existing.address.trim().length < 3;
        existing._unverified = existing._noAddr && (!existing.phone || existing.phone.trim().length < 5);
      }
    });
    return result;
  };

  // ── Search (multi-round) ──────────────────────────────────

  // ── Stop search ────────────────────────────────────────────
  const stopSearch = useCallback(() => {
    if (searchAbortRef.current) searchAbortRef.current.abort();
    if (searchTimerRef.current) clearInterval(searchTimerRef.current);
    setSearchTimeLeft(0);
    setSearchPass(0);
    setNextPassIn(0);
    setCurrentBatchLabel("");
    setCurrentBatchTag("");
    setVerifying(false);
    setVerifyProgress("");
    setLoading(false);
  }, []);

  const resetSearch = useCallback(() => {
    stopSearch();
    setQuery(""); setCity(""); setState("");
    setResults([]); setError(null);
    setAdvCuisine(""); setAdvHalal("");
  }, [stopSearch]);

  // ── Search (batch-based multi-pass) ───────────────────────
  const handleSearch = async (overrideQuery) => {
    const q = overrideQuery || query;
    if (!q.trim() && !city.trim() && !state.trim()) return;

    const abortController = new AbortController();
    searchAbortRef.current = abortController;
    const startTime = Date.now();

    setLoading(true); setError(null); setResults([]);
    setSearchPass(0); setNextPassIn(0);
    setSearchTimeLeft(deepSearch ? -1 : 300);

    // Timer
    searchTimerRef.current = setInterval(() => {
      const elapsed = Math.floor((Date.now() - startTime) / 1000);
      if (deepSearch) {
        setSearchTimeLeft(-elapsed);
      } else {
        const remaining = 300 - elapsed;
        if (remaining <= 0) {
          abortController.abort();
          clearInterval(searchTimerRef.current);
          setSearchTimeLeft(0);
        } else {
          setSearchTimeLeft(remaining);
        }
      }
    }, 1000);

    // Always append location
    const location = [city.trim(), state.trim()].filter(Boolean).join(", ");
    const fullQuery = location ? `in ${location}` : "";
    const extra = advCuisine ? `Cuisine: ${advCuisine}. ` : "";

    let allResults = [];
    let batchesCompleted = 0;

    const searchBatch = async (batch) => {
      if (abortController.signal.aborted) return [];
      try {
        const resp = await fetch("/api/search", {
          method: "POST", headers: { "Content-Type": "application/json" },
          signal: abortController.signal,
          body: JSON.stringify({
            model: "claude-sonnet-4-20250514", max_tokens: 4096,
            tools: [{ type: "web_search_20250305", name: "web_search" }],
            messages: [{ role: "user", content: batch.prompt(fullQuery, extra) }],
          }),
        });
        if (resp.status === 429) {
          const retryAfter = resp.headers.get("retry-after");
          setError(`⏳ Rate limit hit — try again ${retryAfter ? `in ${retryAfter}s` : "in a few minutes"}. Try during off-peak hours (evenings/weekends PT).`);
          abortController.abort();
          return [];
        }
        if (resp.status === 529) {
          setError("🔧 API is overloaded — Anthropic servers are busy. Try again in a few minutes.");
          abortController.abort();
          return [];
        }
        if (!resp.ok) {
          const errBody = await resp.json().catch(() => ({}));
          const errMsg = errBody?.error?.message || "";
          if (/rate|limit|quota|capacity|overloaded/i.test(errMsg)) {
            setError(`⏳ ${errMsg || "Rate limit reached"} — try again later or during off-peak hours.`);
            abortController.abort();
            return [];
          }
          console.error(`API error ${resp.status}:`, errMsg);
          return [];
        }
        const data = await resp.json();
        if (data.error) {
          const errMsg = data.error.message || data.error.type || "";
          if (/rate|limit|quota|capacity|overloaded/i.test(errMsg)) {
            setError(`⏳ ${errMsg} — try again later or during off-peak hours.`);
            abortController.abort();
            return [];
          }
          return [];
        }
        return parseResults(data);
      } catch (e) {
        if (e.name === "AbortError") return [];
        console.error(`"${batch.label}" failed:`, e);
        return [];
      }
    };

    // Loop prefixes for after all 30 passes complete
    const LOOP_PREFIXES = ["best ", "top rated ", "popular ", "recommended ", "new ", "authentic ", "hidden gem "];
    let loopRound = 0;

    try {
      // ── Pass 1: First 3 batches in parallel (always) ─────
      setSearchPass(1);
      setCurrentBatchLabel(INITIAL_BATCHES.map(b => b.label).join(" · "));
      setCurrentBatchTag(INITIAL_BATCHES[0].tag);
      const initialResults = await Promise.all(INITIAL_BATCHES.map(searchBatch));
      if (abortController.signal.aborted) throw { name: "AbortError" };
      allResults = dedup(initialResults.flat());
      setResults([...allResults]);
      batchesCompleted = INITIAL_BATCHES.length;

      // ── Deeper passes (unlimited only) ────────────────────
      if (deepSearch) {
        while (!abortController.signal.aborted) {
          const remainingBatches = ALL_SOURCE_BATCHES.slice(INITIAL_BATCHES.length);

          for (let i = 0; i < remainingBatches.length; i++) {
            if (abortController.signal.aborted) break;
            const batch = remainingBatches[i];

            // 2-minute cooldown
            const PASS_DELAY = 120;
            setNextPassIn(PASS_DELAY);
            setCurrentBatchLabel(`Next: ${batch.label}${loopRound > 0 ? ` (round ${loopRound + 1})` : ""}`);
            setCurrentBatchTag(batch.tag);
            await new Promise((resolve) => {
              let countdown = PASS_DELAY;
              const interval = setInterval(() => {
                countdown--;
                setNextPassIn(countdown);
                if (countdown <= 0 || abortController.signal.aborted) {
                  clearInterval(interval);
                  setNextPassIn(0);
                  resolve();
                }
              }, 1000);
            });

            if (abortController.signal.aborted) break;

            // Search — on loop rounds, modify the batch prompt with a prefix
            const passNum = INITIAL_BATCHES.length + i + (loopRound * remainingBatches.length);
            setSearchPass(passNum + 1);
            setCurrentBatchLabel(batch.label + (loopRound > 0 ? ` (round ${loopRound + 1})` : ""));
            setCurrentBatchTag(batch.tag);

            let batchToSearch = batch;
            if (loopRound > 0) {
              const prefix = LOOP_PREFIXES[(loopRound - 1) % LOOP_PREFIXES.length];
              batchToSearch = { ...batch, prompt: (q2, ex) => batch.prompt(q2, ex).replace(/for: "/g, `for: "${prefix}`) };
            }

            const batchResults = await searchBatch(batchToSearch);
            if (abortController.signal.aborted) break;

            allResults = dedup([...allResults, ...batchResults]);
            setResults([...allResults]);
            batchesCompleted++;
          }

          // Loop back with modified queries
          loopRound++;
          if (abortController.signal.aborted) break;
        }
      }

      const final = dedup(allResults);
      setResults(final);

      // ── AI Verification Pass — cross-check results ─────
      if (final.length > 0 && !abortController.signal.aborted) {
        setVerifying(true);
        setCurrentBatchLabel("Verifying results...");
        const verified = [...final];
        const batchSize = 5;

        for (let i = 0; i < verified.length; i += batchSize) {
          if (abortController.signal.aborted) break;
          const batch = verified.slice(i, i + batchSize);
          setVerifyProgress(`Verifying ${i+1}-${Math.min(i+batchSize, verified.length)} of ${verified.length}`);

          try {
            const names = batch.map((r, j) => `${i+j+1}. "${r.name}" at "${r.address || 'no address'}" phone: ${r.phone || 'none'}`).join("\n");
            const resp = await fetch("/api/search", {
              method: "POST", headers: { "Content-Type": "application/json" },
              signal: abortController.signal,
              body: JSON.stringify({
                messages: [{ role: "user", content: `Search the web for each of these restaurants. For each one, look up the restaurant name + city to verify it actually exists. Check Google Maps, Yelp, or any business listing.

${names}

For EACH restaurant, search for it and report:
- Does a real business listing exist for this exact name in this city?
- What is the correct address from the listing you found?
- What is the correct phone number from the listing?
- Does the listing mention halal?

IMPORTANT: If you CANNOT find a real listing for a restaurant, mark exists as false. Do NOT guess.

Return ONLY a JSON array, one object per restaurant in order:
[{"index":1,"exists":true/false,"nameCorrect":"exact name from listing or same","addressCorrect":"exact address from listing or same","phoneCorrect":"phone from listing or same","isHalal":true/false/null,"note":"source URL or brief note"}]
No markdown, no backticks, ONLY the JSON array.` }],
              }),
            });
            if (resp.ok) {
              const data = await resp.json();
              const text = (data.content || []).map(b => b.text || "").join("");
              const checks = safeParseJsonArray(text);
              if (checks.length > 0) {
                checks.forEach((check) => {
                  const idx = (check.index || 1) - 1;
                  const realIdx = i + idx;
                  if (realIdx < verified.length && check) {
                    if (check.exists === false) {
                      verified[realIdx]._removed = true;
                      verified[realIdx]._verifyNote = "Not found — may not exist";
                    } else {
                      verified[realIdx]._verified = true;
                      if (check.nameCorrect && check.nameCorrect !== "same" && norm(check.nameCorrect) !== norm(verified[realIdx].name)) {
                        verified[realIdx]._verifyNote = `AI suggests: ${check.nameCorrect}`;
                      }
                      if (check.addressCorrect && check.addressCorrect !== "same" && check.addressCorrect.length > 5 && norm(check.addressCorrect) !== norm(verified[realIdx].address)) {
                        verified[realIdx].address = check.addressCorrect;
                        verified[realIdx].gmaps = autoGmaps(verified[realIdx].name, check.addressCorrect);
                      }
                      if (check.phoneCorrect && check.phoneCorrect !== "same" && check.phoneCorrect.length > 5) {
                        verified[realIdx].phone = check.phoneCorrect;
                      }
                      if (check.isHalal === false) {
                        verified[realIdx]._verifyNote = "AI could not confirm halal status";
                        verified[realIdx].halalLevel = "Unverified";
                      }
                      if (check.note) {
                        verified[realIdx].notes = [verified[realIdx].notes, check.note].filter(Boolean).join(" | ");
                      }
                    }
                  }
                });
              }
            }
          } catch(e) {
            if (e.name === "AbortError") break;
            console.error("Verify batch failed:", e);
          }
        }

        // Remove non-existent restaurants, keep the rest
        const cleaned = verified.filter(r => !r._removed);
        setResults(cleaned);
        setVerifying(false);
        setVerifyProgress("");
        setCurrentBatchLabel("");

        if (cleaned.length) {
          const newCount = cleaned.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db)).length;
          const verifiedCount = cleaned.filter(r => r._verified).length;
          const removedCount = verified.length - cleaned.length;
          const elapsed = Math.floor((Date.now() - startTime) / 1000);
          const mins = Math.floor(elapsed / 60);
          const secs = elapsed % 60;
          showToast(`✅ ${verifiedCount} verified · ${removedCount > 0 ? removedCount + " removed · " : ""}${newCount} new · ${mins}m ${secs}s`);
        } else {
          setError("No verified restaurants found — try a different city");
        }
      } else if (final.length) {
        const newCount = final.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db)).length;
        const elapsed = Math.floor((Date.now() - startTime) / 1000);
        const mins = Math.floor(elapsed / 60);
        const secs = elapsed % 60;
        showToast(`Found ${newCount} new out of ${final.length} total · ${batchesCompleted} passes · ${mins}m ${secs}s`);
      } else {
        setError("No restaurants found — try a different city or search term");
      }

      setTimeout(() => resultsRef.current?.scrollIntoView({ behavior:"smooth" }), 300);
    } catch (e) {
      if (e.name !== "AbortError") setError(e.message || "Search failed");
    } finally {
      clearInterval(searchTimerRef.current);
      setSearchTimeLeft(0);
      setSearchPass(0);
      setNextPassIn(0);
      setCurrentBatchLabel("");
      setCurrentBatchTag("");
      setLoading(false);
    }
  };

  const handlePreset = (p) => {
    setShowPresets(false);
    const location = [city.trim(), state.trim()].filter(Boolean).join(", ");
    if (p.type === "cuisine") {
      const q = `halal ${p.label} restaurants${location ? " in " + location : ""}`;
      setQuery(`halal ${p.label} restaurants`);
      handleSearch(q);
    } else {
      const base = p.label === "Near Me" ? "halal restaurants near me" : `${p.label.toLowerCase()} halal restaurants`;
      const q = location && p.label !== "Near Me" ? `${base} in ${location}` : base;
      setQuery(base);
      handleSearch(q);
    }
  };

  // ── Add / Remove ──────────────────────────────────────────────
  const addToDb = (r) => {
    if (isKnown(r.name, r.address, r.phone, r.website, db)) { showToast(`⚠️ "${r.name}" looks like a duplicate!`); return; }
    setEditModal(r); setEditIsNew(true);
  };
  const confirmAdd = (r) => {
    const entry = { ...r, addedAt: new Date().toISOString() };
    const prev = [...db];
    const next = [...db, entry];
    persistDb(next);
    setEditModal(null);
    showToast(`✅ Added "${r.name}"`, () => persistDb(prev));
  };
  const addAllNew = () => {
    const newOnes = results.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db));
    if (!newOnes.length) return;
    const prev = [...db];
    const next = [...db, ...newOnes.map(r => ({ ...r, halalLevel: "Unverified", addedAt: new Date().toISOString() }))];
    persistDb(next);
    showToast(`✅ Added ${newOnes.length} restaurants`, () => persistDb(prev));
  };
  const addToFaves = (r) => {
    if (faves.some(f => norm(f.name) === norm(r.name))) { showToast(`⭐ "${r.name}" already in favorites`); return; }
    const entry = { ...r, favedAt: new Date().toISOString() };
    persistFaves([...faves, entry]);
    showToast(`⭐ "${r.name}" added to favorites`);
  };
  const removeFromFaves = (r) => {
    const prev = [...faves];
    persistFaves(faves.filter(f => norm(f.name) !== norm(r.name)));
    showToast(`Removed "${r.name}" from favorites`, () => persistFaves(prev));
  };
  const isFaved = (r) => faves.some(f => norm(f.name) === norm(r.name));

  const saveVerification = (updated) => {
    // Update in DB if exists
    const inDb = db.findIndex(d => norm(d.name) === norm(updated.name));
    if (inDb > -1) {
      const next = [...db]; next[inDb] = { ...next[inDb], ...updated };
      persistDb(next);
    }
    // Update in faves if exists
    const inFav = faves.findIndex(f => norm(f.name) === norm(updated.name));
    if (inFav > -1) {
      const next = [...faves]; next[inFav] = { ...next[inFav], ...updated };
      persistFaves(next);
    }
    showToast(`📞 "${updated.name}" verified as ${updated.halalLevel}`);
    setVerifyModal(null);
  };
  const moveToTrash = (r) => {
    setConfirmModal({ title: "Move to Trash?", message: `"${r.name}" will be moved to trash.`, onConfirm: () => {
      persistDb(db.filter(d => norm(d.name) !== norm(r.name)));
      persistTrash([...trash, { ...r, trashedAt: new Date().toISOString() }]);
      setConfirmModal(null);
      showToast(`🗑️ "${r.name}" moved to trash`);
    }});
  };
  const restoreFromTrash = (r) => {
    persistTrash(trash.filter(d => norm(d.name) !== norm(r.name)));
    persistDb([...db, r]);
    showToast(`♻️ "${r.name}" restored`);
  };
  const permDelete = (r) => {
    setConfirmModal({ title: `Delete "${r.name}"?`, message: "This action cannot be undone.", danger: true, onConfirm: () => {
      persistTrash(trash.filter(d => norm(d.name) !== norm(r.name)));
      setConfirmModal(null);
    }});
  };
  const emptyTrash = () => {
    setConfirmModal({ title: "Empty All Trash?", message: `Permanently delete ${trash.length} restaurant${trash.length!==1?"s":""}?`, danger: true, onConfirm: () => { persistTrash([]); setConfirmModal(null); }});
  };
  const saveEdit = (r) => {
    if (editIsNew) { confirmAdd(r); return; }
    persistDb(db.map(d => norm(d.name) === norm(editModal.name) ? { ...d, ...r } : d));
    setEditModal(null); showToast(`✏️ Updated "${r.name}"`);
  };

  // ── Bulk ──────────────────────────────────────────────────────
  const toggleSelect = (r) => {
    const key = norm(r.name);
    setSelected(prev => { const next = new Set(prev); next.has(key) ? next.delete(key) : next.add(key); return next; });
  };
  const bulkTrash = () => {
    const toRemove = db.filter(r => selected.has(norm(r.name)));
    persistDb(db.filter(r => !selected.has(norm(r.name))));
    persistTrash([...trash, ...toRemove.map(r => ({ ...r, trashedAt: new Date().toISOString() }))]);
    setSelected(new Set()); setSelectMode(false);
    showToast(`🗑️ Moved ${toRemove.length} to trash`);
  };

  // ── Derived ───────────────────────────────────────────────────
  const knownResults = results.filter(r => isKnown(r.name, r.address, r.phone, r.website, db));
  const trashedResults = results.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db) && isKnown(r.name, r.address, r.phone, r.website, trash));
  const maybeResults = results.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db) && !isKnown(r.name, r.address, r.phone, r.website, trash) && isMaybeDuplicate(r.name, r.address, r.phone, r.website, db));
  const newResults = results.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db) && !isKnown(r.name, r.address, r.phone, r.website, trash) && !isMaybeDuplicate(r.name, r.address, r.phone, r.website, db));
  const filteredDb = db
    .filter(r => !dbViewState || dbViewState === "all" || (r._crawlState || "").toLowerCase().replace(/\s+/g, "-") === dbViewState)
    .filter(r => !dbFilter || [r.name,r.cuisine,r.address].some(f => norm(f).includes(norm(dbFilter))))
    .filter(r => !dbHalalFilter || r.halalLevel === dbHalalFilter)
    .sort((a, b) => {
      if (dbSort === "name") return (a.name || "").localeCompare(b.name || "");
      if (dbSort === "cuisine") return (a.cuisine || "").localeCompare(b.cuisine || "");
      return new Date(b.addedAt || 0) - new Date(a.addedAt || 0);
    });

  if (!loaded) return <div style={{ height:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"#0f1729", color:"#8892a8", fontFamily:"'JetBrains Mono',monospace" }}>Loading…</div>;

  // ── Crawl functions ──────────────────────────────────────────
  const US_STATES = ["Alabama","Alaska","Arizona","Arkansas","California","Colorado","Connecticut","Delaware","Florida","Georgia","Hawaii","Idaho","Illinois","Indiana","Iowa","Kansas","Kentucky","Louisiana","Maine","Maryland","Massachusetts","Michigan","Minnesota","Mississippi","Missouri","Montana","Nebraska","Nevada","New Hampshire","New Jersey","New Mexico","New York","North Carolina","North Dakota","Ohio","Oklahoma","Oregon","Pennsylvania","Rhode Island","South Carolina","South Dakota","Tennessee","Texas","Utah","Vermont","Virginia","Washington","West Virginia","Wisconsin","Wyoming"];

  const fetchCities = async (stateName) => {
    setCrawlState("fetching");
    setCrawlStateName(stateName);
    setCrawlLog([`Fetching cities in ${stateName}...`]);
    try {
      // Load existing state DB
      const stateKey = `hm-db-${stateName.toLowerCase().replace(/\s+/g, "-")}`;
      const existing = await load(stateKey);
      setCrawlStateDb(existing);
      crawlStateDbRef.current = existing;
      if (existing.length) setCrawlLog(prev => [...prev, `📊 Existing ${stateName} DB: ${existing.length} restaurants`]);

      const resp = await fetch("/api/crawl", {
        method: "POST", headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "cities", state: stateName }),
      });
      const data = await resp.json();
      if (data.error) throw new Error(data.error.message);
      const text = data.cities || "[]";
      const m = text.match(/\[[\s\S]*\]/);
      if (m) {
        let cities;
        try { cities = JSON.parse(m[0]); } catch(e) { cities = safeParseJsonArray(text).map(r => r.name || r); }
        cities = (Array.isArray(cities) ? cities : []).filter(c => typeof c === "string" && c.trim());
        setCrawlCities(cities);
        setCrawlSelectedCities(new Set(cities));
        setCrawlCityIdx(0);
        setCrawlState("idle");
        setCrawlLog(prev => [...prev, `Found ${cities.length} cities in ${stateName}`]);
        return cities;
      }
      throw new Error("Could not parse city list");
    } catch(e) {
      setCrawlLog(prev => [...prev, `❌ Failed: ${e.message}`]);
      setCrawlState("idle");
      return [];
    }
  };

  const saveToStateDb = async (newEntries) => {
    const stateKey = `hm-db-${crawlStateName.toLowerCase().replace(/\s+/g, "-")}`;
    const updated = [...crawlStateDbRef.current, ...newEntries];
    crawlStateDbRef.current = updated;
    setCrawlStateDb(updated);
    await save(stateKey, updated);
    // Also add to main DB
    const mainUpdated = [...dbRef.current, ...newEntries];
    persistDb(mainUpdated);
    // Track state in available list
    setAvailableStates(prev => {
      const sn = crawlStateName.toLowerCase().replace(/\s+/g, "-");
      return prev.includes(sn) ? prev : [...prev, sn];
    });
  };

  const startCrawl = async (fromIdx = 0, fromPass = 0) => {
    const citiesToCrawl = crawlCities.filter(c => crawlSelectedCities.has(c));
    if (!citiesToCrawl.length) { setCrawlLog(prev => [...prev, "⚠️ No cities selected"]); return; }
    const abortController = new AbortController();
    crawlAbortRef.current = abortController;
    setCrawlState("crawling");
    setCrawlCityIdx(fromIdx);

    const startTime = Date.now();
    crawlTimerRef.current = setInterval(() => {
      setCrawlElapsed(Math.floor((Date.now() - startTime) / 1000));
    }, 1000);

    let totalFound = crawlFound;
    let totalNew = crawlNewFound;

    for (let i = fromIdx; i < citiesToCrawl.length; i++) {
      if (abortController.signal.aborted) break;
      const cityName = citiesToCrawl[i];
      setCrawlCityIdx(i);
      setCrawlLog(prev => [...prev.slice(-80), `\n━━━ ${cityName}, ${crawlStateName} (City ${i+1}/${citiesToCrawl.length}) ━━━`]);

      let cityFound = 0;
      let cityNew = 0;
      const startPass = (i === fromIdx) ? fromPass : 0;

      // 10 passes per city
      for (let p = startPass; p < PASSES_PER_CITY; p++) {
        if (abortController.signal.aborted) break;
        setCrawlCityPass(p);
        const passLabels = ["🔥 Zabihah","🔥 Yelp","🔥 Google Maps","🔥 TripAdvisor","🔥 DoorDash","🔥 UberEats","🔥 GrubHub","🔥 Social Media","🔥 Google Reviews","🔥 Hidden Gems"];
        const passLabel = passLabels[p % passLabels.length];
        setCrawlLog(prev => [...prev.slice(-80), `  Pass ${p+1}/${PASSES_PER_CITY}: ${passLabel}`]);

        try {
          const resp = await fetch("/api/crawl", {
            method: "POST", headers: { "Content-Type": "application/json" },
            signal: abortController.signal,
            body: JSON.stringify({ city: cityName, state: crawlStateName, pass: p }),
          });

          if (resp.status === 429) {
            setCrawlLog(prev => [...prev, `    ⏳ Rate limit — waiting 60s...`]);
            await new Promise(r => setTimeout(r, 60000));
            p--; // Retry this pass
            continue;
          }

          if (resp.ok) {
            let data;
            const rawText = await resp.text();
            try {
              data = JSON.parse(rawText);
            } catch(parseErr) {
              // Response was truncated or malformed — try to extract what we can
              const extracted = safeParseJsonArray(rawText);
              if (extracted.length > 0) {
                data = { content: [{ type: "text", text: JSON.stringify(extracted) }], method: "recovered" };
              } else {
                setCrawlLog(prev => [...prev.slice(-80), `    ⚠️ Bad response, skipping`]);
                continue;
              }
            }
            const method = data.method || "unknown";
            const text = (data.content || []).map(b => b.text || "").join("");
            const restaurants_raw = safeParseJsonArray(text);
            if (restaurants_raw.length > 0) {
              let restaurants = restaurants_raw.filter(r => r && r.name)
              restaurants = restaurants
                .filter(r => !isNonRestaurant(r))
                .map(r => ({
                  ...r,
                  _crawlState: crawlStateName,
                  _crawlCity: cityName,
                  halalLevel: r.halalLevel || detectHalalLevel(r),
                  gmaps: r.gmaps || autoGmaps(r.name, r.address),
                  addedAt: new Date().toISOString(),
                  source: r.source || method,
                }));

              // Dedup against both state DB and main DB
              const newOnes = restaurants.filter(r =>
                !isKnown(r.name, r.address, r.phone, r.website, crawlStateDbRef.current) &&
                !isKnown(r.name, r.address, r.phone, r.website, dbRef.current)
              );

              if (newOnes.length > 0) {
                await saveToStateDb(newOnes);
                cityNew += newOnes.length;
                totalNew += newOnes.length;
                setCrawlNewFound(totalNew);
              }
              cityFound += restaurants.length;
              totalFound += restaurants.length;
              setCrawlFound(totalFound);
              setCrawlLog(prev => [...prev.slice(-80), `    ✅ ${restaurants.length} found, ${newOnes.length} new (${method})`]);
            } else {
              setCrawlLog(prev => [...prev.slice(-80), `    ⬜ No results`]);
            }
          }
        } catch(e) {
          if (e.name === "AbortError") break;
          setCrawlLog(prev => [...prev.slice(-80), `    ❌ ${e.message || "error"}`]);
        }

        // 60s cooldown between passes (unless last pass of city)
        if (p < PASSES_PER_CITY - 1 && !abortController.signal.aborted) {
          for (let c = PASS_COOLDOWN; c > 0; c--) {
            if (abortController.signal.aborted) break;
            setCrawlCooldown(c);
            await new Promise(r => setTimeout(r, 200));
          }
          setCrawlCooldown(0);
        }
      }

      setCrawlLog(prev => [...prev.slice(-80), `  📊 ${cityName} total: ${cityFound} found, ${cityNew} new added`]);
      setCrawlCityPass(0);

      // 30s cooldown between cities
      if (i < citiesToCrawl.length - 1 && !abortController.signal.aborted) {
        setCrawlLog(prev => [...prev.slice(-80), `  ⏳ Next city in 30s...`]);
        for (let c = 30; c > 0; c--) {
          if (abortController.signal.aborted) break;
          setCrawlCooldown(c);
          await new Promise(r => setTimeout(r, 200));
        }
        setCrawlCooldown(0);
      }
    }

    clearInterval(crawlTimerRef.current);
    if (!abortController.signal.aborted) {
      setCrawlState("done");
      const stateKey = `hm-db-${crawlStateName.toLowerCase().replace(/\s+/g, "-")}`;
      setCrawlLog(prev => [...prev, `\n🎉 ${crawlStateName} crawl complete!\n📊 ${totalFound} total found, ${totalNew} new added\n💾 Saved to ${stateKey} (${crawlStateDbRef.current.length} total in state DB)`]);
      showToast(`🎉 ${crawlStateName} done — ${totalNew} new restaurants`);
    }
  };

  const pauseCrawl = () => {
    if (crawlAbortRef.current) crawlAbortRef.current.abort();
    clearInterval(crawlTimerRef.current);
    setCrawlState("paused");
    setCrawlCooldown(0);
    setCrawlLog(prev => [...prev, `⏸️ Paused at city ${crawlCityIdx + 1}/${crawlCities.length}, pass ${crawlCityPass + 1}/${PASSES_PER_CITY}`]);
  };

  const resumeCrawl = () => {
    startCrawl(crawlCityIdx, crawlCityPass + 1 >= PASSES_PER_CITY ? 0 : crawlCityPass + 1);
    if (crawlCityPass + 1 >= PASSES_PER_CITY) setCrawlCityIdx(prev => prev + 1);
  };

  const resetCrawl = () => {
    if (crawlAbortRef.current) crawlAbortRef.current.abort();
    clearInterval(crawlTimerRef.current);
    setCrawlState("idle");
    setCrawlStateName("");
    setCrawlCities([]);
    setCrawlSelectedCities(new Set());
    setCrawlCityIdx(0);
    setCrawlFound(0);
    setCrawlNewFound(0);
    setCrawlLog([]);
    setCrawlElapsed(0);
    setCrawlCooldown(0);
    setCrawlCityPass(0);
    setCrawlStateDb([]);
    crawlStateDbRef.current = [];
  };

  const tabData = [
    { id: "search", label: "Search", icon: <Search size={15}/>, badge: loading ? results.length : (newResults.length || null) },
    { id: "crawl", label: "Crawl", icon: <Globe size={15}/>, badge: crawlState === "crawling" ? crawlNewFound || "…" : null },
    { id: "database", label: "Database", icon: <Database size={15}/>, badge: db.length || null },
    { id: "faves", label: "Faves", icon: <Star size={15}/>, badge: faves.length || null },
    { id: "trash", label: "Trash", icon: <Trash2 size={15}/>, badge: trash.length || null },
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=Playfair+Display:wght@600;700;800&family=Outfit:wght@300;400;500;600;700&display=swap');
        @keyframes fadeUp{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
        @keyframes pulse{0%,100%{opacity:.45}50%{opacity:1}}
        @keyframes slideDown{from{max-height:0;opacity:0}to{max-height:300px;opacity:1}}
        *{box-sizing:border-box;margin:0;padding:0}
        input:focus,button:focus{outline:none}
        ::-webkit-scrollbar{width:5px}
        ::-webkit-scrollbar-thumb{background:${t.muted};border-radius:99px}
        body{overflow-x:hidden}
      `}</style>

      <div style={{ minHeight:"100vh", background:t.bg, fontFamily:"'Outfit',sans-serif", color:t.text }}>

        {/* ── HEADER ──────────────────────────────────────── */}
        <div style={{ background:"linear-gradient(135deg, #0a1628 0%, #1e3a5f 50%, #2d2d2d 100%)", padding:"24px 16px 16px", color:"#fff", position:"relative", overflow:"hidden" }}>
          <div style={{ position:"absolute", inset:0, background:"radial-gradient(circle at 20% 30%, rgba(37,99,235,.2) 0%, transparent 50%), radial-gradient(circle at 80% 70%, rgba(37,99,235,.12) 0%, transparent 40%)" }}/>
          <div style={{ position:"relative" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <h1 style={{ fontFamily:"'Playfair Display',Georgia,serif", fontSize:22, fontWeight:800, letterSpacing:".01em" }}>Halal Maniacs</h1>
                <p style={{ fontSize:11, opacity:0.6, fontFamily:"'JetBrains Mono',monospace", marginTop:2 }}>{db.length} restaurant{db.length!==1?"s":""} in database</p>
              </div>
              <button onClick={()=>setSettingsModal(true)} style={{ background:"rgba(255,255,255,.1)", border:"none", borderRadius:8, padding:8, cursor:"pointer", color:"#fff" }}><Settings size={18}/></button>
            </div>

            {/* Tabs */}
            <div style={{ display:"flex", gap:4, marginTop:14, background:"rgba(0,0,0,.25)", borderRadius:10, padding:3 }}>
              {tabData.map(td => (
                <button key={td.id} onClick={()=>{setTab(td.id);setSelectMode(false);setSelected(new Set());}} style={{ flex:1, padding:"8px 0", border:"none", borderRadius:8, background: tab===td.id ? "#fff" : "transparent", color: tab===td.id ? "#1e3a5f" : "rgba(255,255,255,.6)", fontWeight:700, fontSize:12, cursor:"pointer", transition:"all .2s", display:"flex", alignItems:"center", justifyContent:"center", gap:5, position:"relative", fontFamily:"'Outfit',sans-serif" }}>
                  {td.icon}{td.label}
                  {td.badge > 0 && <span style={{ background: tab===td.id ? "#2563eb" : "rgba(255,255,255,.25)", color:"#fff", fontSize:9, fontWeight:800, padding:"1px 6px", borderRadius:99, fontFamily:"'JetBrains Mono',monospace" }}>{td.badge}</span>}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* ── TOUR BANNER ──────────────────────────────────── */}
        {tourBanner && (
          <div style={{ background:"#2563eb", color:"#fff", padding:"10px 16px", fontSize:12, display:"flex", alignItems:"center", gap:8 }}>
            <Info size={16}/>
            <span style={{ flex:1 }}>Search for halal restaurants, add them to your database, and manage your collection. Tap cards to expand details.</span>
            <button onClick={()=>{setTourBanner(false);save(TOUR_KEY,true);}} style={{ background:"rgba(255,255,255,.2)", border:"none", borderRadius:6, padding:"4px 10px", color:"#fff", fontWeight:700, fontSize:11, cursor:"pointer", whiteSpace:"nowrap" }}>Got it</button>
          </div>
        )}

        {/* ── BODY ────────────────────────────────────────── */}
        <div style={{ maxWidth:560, margin:"0 auto", padding:"12px 12px 60px" }}>

          {/* Toast */}
          {toast && (
            <div style={{ background:"#1e3a5f", color:"#fff", padding:"10px 14px", borderRadius:10, fontSize:12, fontWeight:600, marginBottom:10, animation:"fadeUp .25s ease", display:"flex", alignItems:"center", gap:8, fontFamily:"'JetBrains Mono',monospace" }}>
              <span style={{ flex:1 }}>{toast.msg}</span>
              {toast.undoFn && <button onClick={()=>{toast.undoFn();setToast(null);}} style={{ background:"rgba(255,255,255,.2)", border:"none", borderRadius:6, padding:"4px 10px", color:"#fff", fontWeight:700, fontSize:11, cursor:"pointer" }}>Undo</button>}
            </div>
          )}

          {/* ═══ SEARCH TAB ════════════════════════════════ */}
          {tab === "search" && (
            <>
              <div style={{ display:"flex", gap:6, marginBottom:6 }}>
                <div style={{ position:"relative", flex:1 }}>
                  <input value={query} onChange={e=>setQuery(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSearch()} placeholder="Search halal restaurants…" style={{ width:"100%", padding:"11px 14px", borderRadius:10, border:`1.5px solid ${t.inputBorder}`, fontSize:13, fontFamily:"inherit", background:t.input, color:t.text, transition:"border .2s", boxSizing:"border-box" }} onFocus={e=>e.target.style.borderColor="#2563eb"} onBlur={e=>e.target.style.borderColor=t.inputBorder} />
                </div>
                <div style={{ position:"relative" }}>
                  <button onClick={()=>setShowPresets(!showPresets)} style={{ height:"100%", padding:"0 12px", border:`1.5px solid ${t.inputBorder}`, borderRadius:10, background:t.input, color:t.text, fontSize:12, cursor:"pointer", display:"flex", alignItems:"center", gap:4 }}>Presets <ChevronDown size={13}/></button>
                  {showPresets && (
                    <div style={{ position:"absolute", top:"100%", right:0, marginTop:4, background:t.card, border:`1px solid ${t.cardBorder}`, borderRadius:10, padding:6, width:200, zIndex:100, boxShadow:"0 8px 24px rgba(0,0,0,.15)", maxHeight:280, overflowY:"auto" }}>
                      <div style={{ fontSize:9, fontWeight:700, color:t.muted, textTransform:"uppercase", padding:"4px 8px", fontFamily:"'JetBrains Mono',monospace" }}>Location</div>
                      {ALL_PRESETS.filter(p=>p.type==="location").map(p => <button key={p.label} onClick={()=>handlePreset(p)} style={{ display:"block", width:"100%", textAlign:"left", padding:"7px 10px", border:"none", background:"transparent", color:t.text, fontSize:12, fontWeight:500, cursor:"pointer", borderRadius:6 }}>{p.label}</button>)}
                      <div style={{ fontSize:9, fontWeight:700, color:t.muted, textTransform:"uppercase", padding:"4px 8px", marginTop:4, fontFamily:"'JetBrains Mono',monospace" }}>Cuisine</div>
                      {ALL_PRESETS.filter(p=>p.type==="cuisine").map(p => <button key={p.label} onClick={()=>handlePreset(p)} style={{ display:"block", width:"100%", textAlign:"left", padding:"7px 10px", border:"none", background:"transparent", color:t.text, fontSize:12, fontWeight:500, cursor:"pointer", borderRadius:6 }}>{p.label}</button>)}
                    </div>
                  )}
                </div>
                <button onClick={()=>setDeepSearch(!deepSearch)} disabled={loading} style={{ padding:"0 10px", border: deepSearch ? "1.5px solid #f59e0b" : `1.5px solid ${t.inputBorder}`, borderRadius:10, background: deepSearch ? "#f59e0b18" : t.input, color: deepSearch ? "#f59e0b" : t.muted, fontWeight:700, fontSize:11, cursor: loading?"not-allowed":"pointer", fontFamily:"'JetBrains Mono',monospace", whiteSpace:"nowrap", height:"auto" }}>{deepSearch ? "♾️" : "⏱️"}</button>
                <button onClick={()=>handleSearch()} disabled={loading} style={{ padding:"0 16px", border:"none", borderRadius:10, background: loading ? t.muted : "linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:13, cursor: loading?"wait":"pointer" }}>{loading ? "…" : "Go"}</button>
              </div>

              {/* City & State */}
              <div style={{ display:"flex", gap:6, marginBottom:8 }}>
                <input value={city} onChange={e=>setCity(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSearch()} placeholder="City" style={{ flex:2, padding:"9px 12px", borderRadius:8, border:`1.5px solid ${t.inputBorder}`, fontSize:12, fontFamily:"inherit", background:t.input, color:t.text, boxSizing:"border-box", transition:"border .2s" }} onFocus={e=>e.target.style.borderColor="#2563eb"} onBlur={e=>e.target.style.borderColor=t.inputBorder} />
                <input value={state} onChange={e=>setState(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSearch()} placeholder="State" style={{ flex:1, padding:"9px 12px", borderRadius:8, border:`1.5px solid ${t.inputBorder}`, fontSize:12, fontFamily:"inherit", background:t.input, color:t.text, boxSizing:"border-box", transition:"border .2s" }} onFocus={e=>e.target.style.borderColor="#2563eb"} onBlur={e=>e.target.style.borderColor=t.inputBorder} />
                {(city || state) && <button onClick={()=>{setCity("");setState("");}} style={{ padding:"0 10px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.muted, cursor:"pointer", fontSize:12 }}><X size={14}/></button>}
              </div>

              {/* Search mode indicator + Advanced toggle */}
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
                <button onClick={()=>setShowAdvanced(!showAdvanced)} style={{ background:"none", border:"none", color:"#2563eb", fontSize:11, fontWeight:600, cursor:"pointer", display:"flex", alignItems:"center", gap:4, fontFamily:"'JetBrains Mono',monospace" }}>
                  {showAdvanced ? <ChevronUp size={13}/> : <ChevronDown size={13}/>} Advanced Filters
                </button>
                <button onClick={()=>setDeepSearch(!deepSearch)} disabled={loading} style={{ display:"flex", alignItems:"center", gap:5, padding:"5px 12px", borderRadius:8, border: deepSearch ? "1.5px solid #f59e0b" : `1.5px solid ${t.inputBorder}`, background: deepSearch ? "#f59e0b15" : "transparent", color: deepSearch ? "#f59e0b" : t.muted, fontSize:10, fontWeight:700, cursor: loading ? "not-allowed" : "pointer", fontFamily:"'JetBrains Mono',monospace", transition:"all .2s" }}>
                  {deepSearch ? `♾️ Unlimited · ${ALL_SOURCE_BATCHES.length} passes` : `⏱️ 5 min limit`}
                </button>
              </div>
              {showAdvanced && (
                <div style={{ animation:"slideDown .3s ease", overflow:"hidden", display:"flex", gap:6, marginBottom:10 }}>
                  <select value={advCuisine} onChange={e=>setAdvCuisine(e.target.value)} style={{ flex:1, padding:"8px 10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:12, fontFamily:"inherit" }}>
                    <option value="">Any Cuisine</option>
                    {CUISINE_PRESETS.map(c=><option key={c} value={c}>{c}</option>)}
                  </select>
                  <select value={advHalal} onChange={e=>setAdvHalal(e.target.value)} style={{ flex:1, padding:"8px 10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:12, fontFamily:"inherit" }}>
                    <option value="">Any Halal Level</option>
                    {HALAL_LEVELS.map(h=><option key={h} value={h}>{h}</option>)}
                  </select>
                </div>
              )}

              {loading && (
                <div style={{ textAlign:"center", padding:20, color:t.sub, fontFamily:"'JetBrains Mono',monospace" }}>
                  {/* Timer + Pass + Found display */}
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:14, marginBottom:12 }}>
                    <div>
                      <div style={{ fontSize:28, fontWeight:800, color: searchTimeLeft > 0 && searchTimeLeft <= 30 ? "#dc2626" : searchTimeLeft > 0 ? "#2563eb" : "#f59e0b", letterSpacing:".05em" }}>
                        {searchTimeLeft > 0
                          ? `${Math.floor(searchTimeLeft/60)}:${String(searchTimeLeft%60).padStart(2,"0")}`
                          : searchTimeLeft < 0
                            ? `${Math.floor(Math.abs(searchTimeLeft)/60)}:${String(Math.abs(searchTimeLeft)%60).padStart(2,"0")}`
                            : "…"
                        }
                      </div>
                      <div style={{ fontSize:9, color:t.muted }}>{deepSearch ? "elapsed" : "remaining"}</div>
                    </div>
                    <div style={{ width:1, height:36, background:t.inputBorder }}/>
                    <div>
                      <div style={{ fontSize:28, fontWeight:800, color:"#2563eb" }}>{searchPass}<span style={{ fontSize:14, color:t.muted }}>/{ALL_SOURCE_BATCHES.length}</span></div>
                      <div style={{ fontSize:9, color:t.muted }}>pass</div>
                    </div>
                    <div style={{ width:1, height:36, background:t.inputBorder }}/>
                    <div>
                      <div style={{ fontSize:28, fontWeight:800, color:"#22c55e" }}>{results.length}</div>
                      <div style={{ fontSize:9, color:t.muted }}>found</div>
                    </div>
                  </div>

                  {/* Current search tag */}
                  {currentBatchTag && (
                    <div style={{ display:"inline-block", padding:"4px 14px", borderRadius:99, background:"#2563eb18", border:"1px solid #2563eb40", color:"#2563eb", fontSize:11, fontWeight:700, marginBottom:10 }}>
                      🔍 "{currentBatchTag}"
                    </div>
                  )}

                  {/* Next pass countdown or searching status */}
                  {nextPassIn > 0 ? (
                    <div style={{ marginBottom:12 }}>
                      <div style={{ fontSize:13, color:"#f59e0b", fontWeight:700, marginBottom:4 }}>
                        Next pass in {Math.floor(nextPassIn/60)}:{String(nextPassIn%60).padStart(2,"0")}
                      </div>
                      <div style={{ width:"100%", height:4, background:t.inputBorder, borderRadius:99, overflow:"hidden" }}>
                        <div style={{ width:`${((120-nextPassIn)/120)*100}%`, height:"100%", background:"linear-gradient(90deg, #f59e0b, #2563eb)", borderRadius:99, transition:"width 1s linear" }}/>
                      </div>
                      {currentBatchLabel && <div style={{ fontSize:11, color:"#f59e0b", marginTop:6, fontWeight:600 }}>{currentBatchLabel}</div>}
                      <div style={{ fontSize:9, color:t.muted, marginTop:3 }}>All 29 platforms · {results.length} found · Pass {searchPass}/{ALL_SOURCE_BATCHES.length}</div>
                    </div>
                  ) : (
                    <>
                      <div style={{ fontSize:12, animation:"pulse 1.4s ease infinite", marginBottom:6 }}>
                        Searching all platforms…
                      </div>
                      {deepSearch && (
                        <div style={{ width:"100%", height:3, background:t.inputBorder, borderRadius:99, overflow:"hidden", marginBottom:8 }}>
                          <div style={{ width:`${(searchPass / ALL_SOURCE_BATCHES.length)*100}%`, height:"100%", background:"linear-gradient(90deg, #2563eb, #22c55e)", borderRadius:99, transition:"width .5s ease" }}/>
                        </div>
                      )}
                    </>
                  )}

                  <button onClick={stopSearch} style={{ padding:"10px 32px", border:"none", borderRadius:8, background:"#dc2626", color:"#fff", fontWeight:700, fontSize:13, cursor:"pointer", fontFamily:"'JetBrains Mono',monospace" }}>⏹ Stop Search</button>
                  {results.length > 0 && <div style={{ marginTop:8, fontSize:11, color:t.muted }}>Results appear above — stop anytime to keep them</div>}
                </div>
              )}
              {verifying && !loading && (
                <div style={{ textAlign:"center", padding:20, color:t.sub, fontFamily:"'JetBrains Mono',monospace" }}>
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:10, marginBottom:12 }}>
                    <div style={{ width:40, height:40, borderRadius:"50%", background:"linear-gradient(135deg,#059669,#10b981)", display:"flex", alignItems:"center", justifyContent:"center", animation:"pulse 1.4s ease infinite" }}>
                      <Check size={20} color="#fff"/>
                    </div>
                  </div>
                  <div style={{ fontSize:13, fontWeight:700, color:t.text, marginBottom:4 }}>Verifying Results</div>
                  <div style={{ fontSize:11, color:t.muted, marginBottom:8 }}>Cross-checking each restaurant against real listings...</div>
                  {verifyProgress && <div style={{ fontSize:11, color:"#059669", fontWeight:600 }}>{verifyProgress}</div>}
                </div>
              )}
              {error && (
                <div style={{ background: error.startsWith("⏳") || error.startsWith("🔧") ? "#fffbeb" : "#fef2f2", color: error.startsWith("⏳") || error.startsWith("🔧") ? "#92400e" : "#dc2626", padding:"12px 14px", borderRadius:10, fontSize:12, marginBottom:10, lineHeight:1.5, border: error.startsWith("⏳") ? "1px solid #f59e0b40" : "none" }}>
                  <div style={{ fontWeight:700, marginBottom: error.startsWith("⏳") || error.startsWith("🔧") ? 6 : 0 }}>{error}</div>
                  {(error.startsWith("⏳") || error.startsWith("🔧")) && (
                    <div style={{ fontSize:11, color:"#78716c", marginTop:4 }}>
                      💡 Tips: Search during off-peak hours (after 11am PT / evenings). Start a new chat to reduce token usage. Use Sonnet instead of Opus.
                    </div>
                  )}
                </div>
              )}

              <div ref={resultsRef} />

              {/* Summary bar */}
              {results.length > 0 && !loading && (
                <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10, padding:"8px 12px", background:t.card, borderRadius:8, border:`1px solid ${t.cardBorder}`, flexWrap:"wrap", gap:4 }}>
                  <span style={{ fontSize:11, fontFamily:"'JetBrains Mono',monospace", color:t.sub }}>
                    {newResults.length} new{maybeResults.length ? ` · ${maybeResults.length} maybe` : ""}{trashedResults.length ? ` · ${trashedResults.length} trashed` : ""} · {knownResults.length} known
                  </span>
                  <div style={{ display:"flex", gap:6 }}>
                    <button onClick={resetSearch} style={{ border:`1px solid ${t.inputBorder}`, borderRadius:6, padding:"5px 12px", background:t.input, color:t.sub, fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"'JetBrains Mono',monospace", display:"flex", alignItems:"center", gap:4 }}><X size={11}/> New City</button>
                    {newResults.length > 1 && <button onClick={addAllNew} style={{ background:"linear-gradient(135deg,#1e3a5f,#2563eb)", border:"none", borderRadius:6, padding:"5px 12px", color:"#fff", fontSize:11, fontWeight:700, cursor:"pointer" }}>+ Add All New</button>}
                  </div>
                </div>
              )}

              {/* New results */}
              {newResults.length > 0 && <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:16 }}>{newResults.map((r,i) => <Card key={i} r={{...r, _noAddr: !r.address || r.address.trim().length < 3}} isNew onAdd={addToDb} onFave={addToFaves} onUnfave={removeFromFaves} faved={isFaved(r)} onVerify={r=>setVerifyModal(r)} onShare={r=>setShareModal(r)} onNav={a=>setNavModal(a)} idx={i} t={t} />)}</div>}

              {/* Maybe duplicates */}
              {maybeResults.length > 0 && (
                <>
                  <div style={{ fontSize:11, fontWeight:700, color:"#f59e0b", textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", marginBottom:6, display:"flex", alignItems:"center", gap:4 }}>⚠️ Maybe Duplicates ({maybeResults.length})</div>
                  <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:16 }}>{maybeResults.map((r,i) => <Card key={i} r={r} isNew onAdd={addToDb} onFave={addToFaves} onUnfave={removeFromFaves} faved={isFaved(r)} onVerify={r=>setVerifyModal(r)} onShare={r=>setShareModal(r)} onNav={a=>setNavModal(a)} idx={i} t={t} />)}</div>
                </>
              )}

              {/* Previously trashed */}
              {trashedResults.length > 0 && (
                <>
                  <div style={{ fontSize:11, fontWeight:700, color:"#dc2626", textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", marginBottom:6, display:"flex", alignItems:"center", gap:4 }}>🗑️ Previously Deleted ({trashedResults.length})</div>
                  <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:16, opacity:0.6 }}>{trashedResults.map((r,i) => <Card key={i} r={r} dimmed idx={i} t={t} />)}</div>
                </>
              )}

              {/* Already known */}
              {knownResults.length > 0 && (
                <>
                  <div style={{ fontSize:11, fontWeight:700, color:t.muted, textTransform:"uppercase", fontFamily:"'JetBrains Mono',monospace", marginBottom:6 }}>Already in Database ({knownResults.length})</div>
                  <div style={{ display:"flex", flexDirection:"column", gap:8 }}>{knownResults.map((r,i) => <Card key={i} r={r} dimmed idx={i} t={t} />)}</div>
                </>
              )}

              {!loading && !results.length && !error && (
                <div style={{ textAlign:"center", padding:"40px 20px", color:t.muted }}>
                  <svg width="64" height="64" viewBox="0 0 64 64" style={{ margin:"0 auto 12px", opacity:0.3 }}><circle cx="28" cy="28" r="20" fill="none" stroke="currentColor" strokeWidth="3"/><line x1="42" y1="42" x2="56" y2="56" stroke="currentColor" strokeWidth="3" strokeLinecap="round"/></svg>
                  <div style={{ fontWeight:600, fontSize:14, marginBottom:4 }}>Discover halal restaurants</div>
                  <div style={{ fontSize:12 }}>Search by city, cuisine, or use presets</div>
                </div>
              )}
            </>
          )}

          {/* ═══ CRAWL TAB ═════════════════════════════════ */}
          {tab === "crawl" && (
            <>
              {crawlState === "idle" && !crawlCities.length && (
                <>
                  <div style={{ fontSize:14, fontWeight:700, color:t.text, marginBottom:4 }}>Crawl an Entire State</div>
                  <div style={{ fontSize:11, color:t.muted, marginBottom:12 }}>Pick a state to search every city for halal restaurants automatically.</div>
                  <div style={{ display:"flex", flexDirection:"column", gap:4, maxHeight:400, overflowY:"auto" }}>
                    {US_STATES.map(s => (
                      <button key={s} onClick={()=>fetchCities(s)} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"12px 14px", border:`1px solid ${t.inputBorder}`, borderRadius:8, background:t.input, color:t.text, fontSize:13, fontWeight:500, cursor:"pointer", textAlign:"left" }}>
                        <span>{s}</span>
                        <ChevronDown size={14} color={t.muted} style={{ transform:"rotate(-90deg)" }}/>
                      </button>
                    ))}
                  </div>
                </>
              )}

              {crawlState === "fetching" && (
                <div style={{ textAlign:"center", padding:40, color:t.sub }}>
                  <div style={{ fontSize:14, fontWeight:700, marginBottom:8, animation:"pulse 1.4s ease infinite" }}>Loading cities in {crawlStateName}...</div>
                  <div style={{ fontSize:11, color:t.muted }}>Fetching all cities sorted by population</div>
                </div>
              )}

              {(crawlCities.length > 0 && crawlState !== "fetching") && (
                <>
                  {/* Header */}
                  <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
                    <div>
                      <div style={{ fontSize:14, fontWeight:700, color:t.text }}>{crawlStateName}</div>
                      <div style={{ fontSize:11, color:t.muted }}>{crawlSelectedCities.size} of {crawlCities.length} cities selected</div>
                    </div>
                    <button onClick={resetCrawl} style={{ padding:"6px 12px", border:`1px solid ${t.inputBorder}`, borderRadius:6, background:t.input, color:t.sub, fontSize:11, fontWeight:600, cursor:"pointer" }}>Change State</button>
                  </div>

                  {/* Stats dashboard */}
                  {crawlState !== "idle" && (
                    <div style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:10, marginBottom:14, padding:"12px", background:t.bg, borderRadius:10, flexWrap:"wrap" }}>
                      <div style={{ textAlign:"center" }}>
                        <div style={{ fontSize:20, fontWeight:800, color:"#2563eb", fontFamily:"'JetBrains Mono',monospace" }}>{crawlCityIdx + 1}<span style={{ fontSize:10, color:t.muted }}>/{crawlSelectedCities.size || crawlCities.length}</span></div>
                        <div style={{ fontSize:9, color:t.muted }}>cities</div>
                      </div>
                      <div style={{ width:1, height:28, background:t.inputBorder }}/>
                      <div style={{ textAlign:"center" }}>
                        <div style={{ fontSize:20, fontWeight:800, color:"#8b5cf6", fontFamily:"'JetBrains Mono',monospace" }}>{crawlCityPass + 1}<span style={{ fontSize:10, color:t.muted }}>/{PASSES_PER_CITY}</span></div>
                        <div style={{ fontSize:9, color:t.muted }}>pass</div>
                      </div>
                      <div style={{ width:1, height:28, background:t.inputBorder }}/>
                      <div style={{ textAlign:"center" }}>
                        <div style={{ fontSize:20, fontWeight:800, color:"#22c55e", fontFamily:"'JetBrains Mono',monospace" }}>{crawlNewFound}</div>
                        <div style={{ fontSize:9, color:t.muted }}>new</div>
                      </div>
                      <div style={{ width:1, height:28, background:t.inputBorder }}/>
                      <div style={{ textAlign:"center" }}>
                        <div style={{ fontSize:20, fontWeight:800, color:"#f59e0b", fontFamily:"'JetBrains Mono',monospace" }}>{crawlStateDb.length}</div>
                        <div style={{ fontSize:9, color:t.muted }}>state DB</div>
                      </div>
                      <div style={{ width:1, height:28, background:t.inputBorder }}/>
                      <div style={{ textAlign:"center" }}>
                        <div style={{ fontSize:20, fontWeight:800, color:t.sub, fontFamily:"'JetBrains Mono',monospace" }}>{Math.floor(crawlElapsed/60)}:{String(crawlElapsed%60).padStart(2,"0")}</div>
                        <div style={{ fontSize:9, color:t.muted }}>time</div>
                      </div>
                    </div>
                  )}

                  {/* Current city + pass + cooldown */}
                  {crawlState === "crawling" && (
                    <div style={{ textAlign:"center", marginBottom:12 }}>
                      {crawlCooldown > 0 ? (
                        <>
                          <div style={{ fontSize:12, color:"#f59e0b", fontWeight:700, marginBottom:4 }}>Next pass in {Math.floor(crawlCooldown/60)}:{String(crawlCooldown%60).padStart(2,"0")}</div>
                          <div style={{ width:"100%", height:4, background:t.inputBorder, borderRadius:99, overflow:"hidden" }}>
                            <div style={{ width:`${((60-crawlCooldown)/60)*100}%`, height:"100%", background:"linear-gradient(90deg, #f59e0b, #2563eb)", borderRadius:99, transition:"width 1s linear" }}/>
                          </div>
                        </>
                      ) : (
                        <div>
                          <div style={{ fontSize:12, color:"#2563eb", fontWeight:600, animation:"pulse 1.4s ease infinite" }}>
                            🔥 {crawlCities[crawlCityIdx]}, {crawlStateName}
                          </div>
                          <div style={{ fontSize:10, color:t.muted, marginTop:2 }}>Pass {crawlCityPass + 1}/{PASSES_PER_CITY}</div>
                        </div>
                      )}
                    </div>
                  )}

                  {/* Progress bar */}
                  {crawlState !== "idle" && (
                    <div style={{ width:"100%", height:6, background:t.inputBorder, borderRadius:99, overflow:"hidden", marginBottom:12 }}>
                      <div style={{ width:`${((crawlCityIdx+1)/(crawlSelectedCities.size || crawlCities.length))*100}%`, height:"100%", background:"linear-gradient(90deg, #2563eb, #22c55e)", borderRadius:99, transition:"width .5s ease" }}/>
                    </div>
                  )}

                  {/* Action buttons */}
                  <div style={{ display:"flex", gap:8, marginBottom:14 }}>
                    {crawlState === "idle" && (
                      <button onClick={()=>startCrawl(0)} style={{ flex:1, padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#059669,#10b981)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>🚀 Start Crawl</button>
                    )}
                    {crawlState === "crawling" && (
                      <button onClick={pauseCrawl} style={{ flex:1, padding:"12px", border:"none", borderRadius:10, background:"#f59e0b", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>⏸ Pause</button>
                    )}
                    {crawlState === "paused" && (
                      <>
                        <button onClick={resumeCrawl} style={{ flex:1, padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#059669,#10b981)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>▶ Resume</button>
                        <button onClick={resetCrawl} style={{ padding:"12px 16px", border:`1px solid ${t.inputBorder}`, borderRadius:10, background:t.input, color:t.sub, fontWeight:700, fontSize:14, cursor:"pointer" }}>Reset</button>
                      </>
                    )}
                    {crawlState === "done" && (
                      <button onClick={resetCrawl} style={{ flex:1, padding:"12px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer" }}>🔄 Crawl Another State</button>
                    )}
                  </div>

                  {/* Live log */}
                  <div style={{ fontSize:11, fontWeight:700, color:t.sub, marginBottom:6, fontFamily:"'JetBrains Mono',monospace" }}>Live Log</div>
                  <div style={{ background:t.bg, borderRadius:8, padding:10, maxHeight:200, overflowY:"auto", fontFamily:"'JetBrains Mono',monospace", fontSize:10, lineHeight:1.6, color:t.muted }}>
                    {crawlLog.map((line, i) => <div key={i}>{line}</div>)}
                    {!crawlLog.length && <div>Waiting to start...</div>}
                  </div>

                  {/* City selection */}
                  {crawlState === "idle" && (
                    <>
                      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:14, marginBottom:6 }}>
                        <div style={{ fontSize:11, fontWeight:700, color:t.sub, fontFamily:"'JetBrains Mono',monospace" }}>
                          {crawlSelectedCities.size}/{crawlCities.length} cities selected
                        </div>
                        <div style={{ display:"flex", gap:6 }}>
                          <button onClick={()=>setCrawlSelectedCities(new Set(crawlCities))} style={{ padding:"4px 10px", border:`1px solid ${t.inputBorder}`, borderRadius:6, background:t.input, color:"#2563eb", fontSize:10, fontWeight:700, cursor:"pointer" }}>Select All</button>
                          <button onClick={()=>setCrawlSelectedCities(new Set())} style={{ padding:"4px 10px", border:`1px solid ${t.inputBorder}`, borderRadius:6, background:t.input, color:"#dc2626", fontSize:10, fontWeight:700, cursor:"pointer" }}>Deselect All</button>
                        </div>
                      </div>
                      {/* Start from city dropdown */}
                      <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                        <span style={{ fontSize:10, fontWeight:700, color:t.sub, fontFamily:"'JetBrains Mono',monospace", whiteSpace:"nowrap" }}>Start from:</span>
                        <select
                          onChange={e => {
                            const idx = parseInt(e.target.value);
                            if (!isNaN(idx)) {
                              setCrawlSelectedCities(new Set(crawlCities.slice(idx)));
                            }
                          }}
                          defaultValue=""
                          style={{ flex:1, padding:"5px 8px", borderRadius:6, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:11, fontFamily:"inherit", cursor:"pointer" }}
                        >
                          <option value="">— pick a city —</option>
                          {crawlCities.map((c, i) => (
                            <option key={i} value={i}>{c} ({crawlCities.length - i} cities)</option>
                          ))}
                        </select>
                      </div>
                      <div style={{ maxHeight:200, overflowY:"auto", fontSize:11, color:t.muted, lineHeight:1.8 }}>
                        {crawlCities.map((c, i) => {
                          const sel = crawlSelectedCities.has(c);
                          return (
                            <span key={i} onClick={() => {
                              setCrawlSelectedCities(prev => {
                                const next = new Set(prev);
                                if (next.has(c)) next.delete(c); else next.add(c);
                                return next;
                              });
                            }} style={{ display:"inline-block", padding:"4px 10px", margin:2, background: sel ? "#2563eb18" : t.bg, borderRadius:6, border: sel ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, color: sel ? "#2563eb" : t.muted, fontWeight: sel ? 700 : 400, cursor:"pointer", userSelect:"none", transition:"all .15s" }}>{c}</span>
                          );
                        })}
                      </div>
                    </>
                  )}
                </>
              )}
            </>
          )}

          {/* ═══ DATABASE TAB ══════════════════════════════ */}
          {tab === "database" && (
            <>
              {/* State filter */}
              {availableStates.length > 0 && (
                <div style={{ display:"flex", gap:6, marginBottom:8, overflowX:"auto", paddingBottom:4 }}>
                  <button onClick={()=>setDbViewState("all")} style={{ padding:"6px 12px", borderRadius:20, border: dbViewState === "all" ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: dbViewState === "all" ? "#2563eb18" : t.input, color: dbViewState === "all" ? "#2563eb" : t.sub, fontSize:11, fontWeight:700, cursor:"pointer", whiteSpace:"nowrap" }}>All States</button>
                  {availableStates.map(s => (
                    <button key={s} onClick={()=>setDbViewState(s)} style={{ padding:"6px 12px", borderRadius:20, border: dbViewState === s ? "2px solid #2563eb" : `1px solid ${t.inputBorder}`, background: dbViewState === s ? "#2563eb18" : t.input, color: dbViewState === s ? "#2563eb" : t.sub, fontSize:11, fontWeight:700, cursor:"pointer", whiteSpace:"nowrap", textTransform:"capitalize" }}>{s.replace(/-/g, " ")}</button>
                  ))}
                </div>
              )}

              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
                <span style={{ fontSize:12, fontFamily:"'JetBrains Mono',monospace", color:t.sub }}>{filteredDb.length} restaurant{filteredDb.length!==1?"s":""}</span>
                <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                  <button onClick={()=>setCompactView(!compactView)} style={{ background:t.input, border:`1px solid ${t.inputBorder}`, borderRadius:6, padding:5, cursor:"pointer", color:t.sub }}>{compactView ? <Grid size={14}/> : <List size={14}/>}</button>
                  <button onClick={()=>{setSelectMode(!selectMode);setSelected(new Set());}} style={{ background: selectMode ? "#2563eb" : t.input, border: selectMode ? "none" : `1px solid ${t.inputBorder}`, borderRadius:6, padding:"4px 10px", cursor:"pointer", color: selectMode ? "#fff" : t.sub, fontSize:11, fontWeight:600 }}>{selectMode ? "Done" : "Select"}</button>
                </div>
              </div>

              {selectMode && selected.size > 0 && (
                <div style={{ display:"flex", gap:6, marginBottom:8, padding:"8px 10px", background:t.card, borderRadius:8, border:`1px solid ${t.cardBorder}`, alignItems:"center" }}>
                  <span style={{ fontSize:11, fontFamily:"'JetBrains Mono',monospace", color:"#2563eb", fontWeight:700 }}>{selected.size} selected</span>
                  <div style={{ flex:1 }}/>
                  <button onClick={bulkTrash} style={{ background:"#dc2626", border:"none", borderRadius:6, padding:"5px 10px", color:"#fff", fontSize:11, fontWeight:700, cursor:"pointer" }}>🗑️ Trash</button>
                </div>
              )}

              <div style={{ display:"flex", gap:6, marginBottom:8 }}>
                <input value={dbFilter} onChange={e=>setDbFilter(e.target.value)} placeholder="Filter…" style={{ flex:1, padding:"9px 12px", borderRadius:8, border:`1px solid ${t.inputBorder}`, fontSize:12, fontFamily:"inherit", background:t.input, color:t.text, boxSizing:"border-box" }} />
                <select value={dbHalalFilter} onChange={e=>setDbHalalFilter(e.target.value)} style={{ padding:"8px 10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:11, fontFamily:"inherit" }}>
                  <option value="">All Levels</option>
                  {HALAL_LEVELS.map(h=><option key={h} value={h}>{h}</option>)}
                </select>
                <select value={dbSort} onChange={e=>setDbSort(e.target.value)} style={{ padding:"8px 10px", borderRadius:8, border:`1px solid ${t.inputBorder}`, background:t.input, color:t.text, fontSize:11, fontFamily:"inherit" }}>
                  <option value="date">Newest</option>
                  <option value="name">A–Z</option>
                  <option value="cuisine">Cuisine</option>
                </select>
              </div>

              {filteredDb.length > 0 ? (
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {filteredDb.map((r,i) => <Card key={norm(r.name)+i} r={r} compact={compactView} onRemove={moveToTrash} onEdit={r=>{setEditModal(r);setEditIsNew(false);}} onFave={addToFaves} onUnfave={removeFromFaves} faved={isFaved(r)} onVerify={r=>setVerifyModal(r)} onShare={r=>setShareModal(r)} onNav={a=>setNavModal(a)} idx={i} t={t} selectable={selectMode} selected={selected.has(norm(r.name))} onSelect={toggleSelect} />)}
                </div>
              ) : (
                <div style={{ textAlign:"center", padding:"40px 20px", color:t.muted }}>
                  <svg width="64" height="64" viewBox="0 0 64 64" style={{ margin:"0 auto 12px", opacity:0.3 }}><rect x="12" y="8" width="40" height="48" rx="4" fill="none" stroke="currentColor" strokeWidth="2.5"/><line x1="20" y1="20" x2="44" y2="20" stroke="currentColor" strokeWidth="2"/><line x1="20" y1="28" x2="38" y2="28" stroke="currentColor" strokeWidth="2"/><line x1="20" y1="36" x2="42" y2="36" stroke="currentColor" strokeWidth="2"/></svg>
                  <div style={{ fontWeight:600, fontSize:14, marginBottom:4 }}>{db.length===0?"No restaurants yet":"No matches"}</div>
                  <div style={{ fontSize:12, marginBottom:10 }}>{db.length===0?"Search & add, or load the California database":"Try a different filter"}</div>
                  {db.length===0 && <button onClick={async()=>{try{const seed=await decompressSeed();if(seed.length){persistDb(seed);showToast(`✅ Loaded ${seed.length} California restaurants`);}}catch(e){showToast("❌ Failed to load seed data");}}} style={{ padding:"10px 24px", border:"none", borderRadius:10, background:"linear-gradient(135deg,#1e3a5f,#2563eb)", color:"#fff", fontWeight:700, fontSize:13, cursor:"pointer", fontFamily:"'JetBrains Mono',monospace" }}>🗺️ Load California Database (2,247)</button>}
                </div>
              )}

            </>
          )}

          {/* ═══ FAVORITES TAB ═══════════════════════════ */}
          {tab === "faves" && (
            <>
              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:8 }}>
                <span style={{ fontSize:12, fontFamily:"'JetBrains Mono',monospace", color:t.sub }}>{faves.length} favorite{faves.length!==1?"s":""}</span>
              </div>
              {faves.length > 0 ? (
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {faves.map((r,i) => <Card key={norm(r.name)+i} r={r} onRemove={removeFromFaves} onVerify={r=>setVerifyModal(r)} onShare={r=>setShareModal(r)} onNav={a=>setNavModal(a)} faved={true} idx={i} t={t} />)}
                </div>
              ) : (
                <div style={{ textAlign:"center", padding:"40px 20px", color:t.muted }}>
                  <Star size={48} style={{ margin:"0 auto 12px", opacity:0.3, display:"block" }} />
                  <div style={{ fontWeight:600, fontSize:14, marginBottom:4 }}>No favorites yet</div>
                  <div style={{ fontSize:12 }}>Tap the ⭐ star on any restaurant to save it here</div>
                </div>
              )}
            </>
          )}

          {/* ═══ TRASH TAB ═════════════════════════════════ */}
          {tab === "trash" && (
            <>
              {trash.length > 0 && (
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
                  <span style={{ fontSize:12, fontFamily:"'JetBrains Mono',monospace", color:t.sub }}>{trash.length} item{trash.length!==1?"s":""}</span>
                  <button onClick={emptyTrash} style={{ background:"#dc2626", border:"none", borderRadius:6, padding:"6px 12px", color:"#fff", fontSize:11, fontWeight:700, cursor:"pointer" }}>Empty All Trash</button>
                </div>
              )}
              {trash.length > 0 ? (
                <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
                  {trash.map((r,i) => <Card key={norm(r.name)+i} r={r} onRestore={restoreFromTrash} onRemove={permDelete} idx={i} t={t} />)}
                </div>
              ) : (
                <div style={{ textAlign:"center", padding:"40px 20px", color:t.muted }}>
                  <svg width="64" height="64" viewBox="0 0 64 64" style={{ margin:"0 auto 12px", opacity:0.3 }}><path d="M16 18h32M24 18V14a2 2 0 012-2h12a2 2 0 012 2v4M20 18l2 32a2 2 0 002 2h16a2 2 0 002-2l2-32" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"/></svg>
                  <div style={{ fontWeight:600, fontSize:14, marginBottom:4 }}>Trash is empty</div>
                  <div style={{ fontSize:12 }}>Removed restaurants appear here</div>
                </div>
              )}
            </>
          )}
        </div>
      </div>

      {/* ── MODALS ──────────────────────────────────────── */}
      {editModal && <EditModal restaurant={editModal} onSave={saveEdit} onClose={()=>setEditModal(null)} t={t} isNew={editIsNew} />}
      {shareModal && <ShareModal r={shareModal} onClose={()=>setShareModal(null)} t={t} />}
      {navModal && <NavChooser address={navModal} onClose={()=>setNavModal(null)} t={t} />}
      {confirmModal && <ConfirmModal title={confirmModal.title} message={confirmModal.message} danger={confirmModal.danger} onConfirm={confirmModal.onConfirm} onCancel={()=>setConfirmModal(null)} t={t} />}
      {verifyModal && <VerifyModal restaurant={verifyModal} onSave={saveVerification} onClose={()=>setVerifyModal(null)} t={t} />}
      {settingsModal && <SettingsModal settings={settings} onSave={persistSettings} onClose={()=>setSettingsModal(false)} db={db} onImport={(imported) => {
        const fresh = imported.filter(r => !isKnown(r.name, r.address, r.phone, r.website, db));
        persistDb([...db, ...fresh.map(r=>({...r, addedAt:new Date().toISOString()}))]);
        showToast(`📥 Imported ${fresh.length} new restaurant${fresh.length!==1?"s":""} (${imported.length - fresh.length} duplicates skipped)`);
      }} t={t} />}
    </>
  );
}
